export interface BookMetadata {
  title: string;
  author: string;
  summary: string;
  genre: string;
  keyTakeaways: string[];
}

export interface PageData {
  imageUrl: string;
  text: string;
}

export enum AppState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  READING = 'READING',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { BookMetadata } from "../types";

export const analyzeBookContent = async (sampleText: string): Promise<BookMetadata> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze the following text from a PDF and extract the book's metadata. 
    If you cannot find specific metadata, please infer it based on the context.

    Text snippet:
    ${sampleText.substring(0, 5000)}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          author: { type: Type.STRING },
          summary: { type: Type.STRING, description: "A high-level summary of the book content" },
          genre: { type: Type.STRING },
          keyTakeaways: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "3-5 key points or takeaways from the text"
          }
        },
        required: ["title", "author", "summary", "genre", "keyTakeaways"]
      }
    }
  });

  return JSON.parse(response.text);
};

import * as pdfjsLib from 'pdfjs-dist';
import { PageData } from '../types';

// PDF.js worker setup
pdfjsLib.GlobalWorkerOptions.workerSrc = `https://cdnjs.cloudflare.com/ajax/libs/pdf.js/${pdfjsLib.version}/pdf.worker.min.js`;

export const loadPdfPages = async (file: File): Promise<PageData[]> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const numPages = pdf.numPages;
  const pages: PageData[] = [];

  for (let i = 1; i <= numPages; i++) {
    const page = await pdf.getPage(i);
    const viewport = page.getViewport({ scale: 1.5 });
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');

    if (context) {
      canvas.height = viewport.height;
      canvas.width = viewport.width;

      await page.render({
        canvasContext: context,
        viewport: viewport
      }).promise;

      const imageUrl = canvas.toDataURL('image/jpeg', 0.8);
      const textContent = await page.getTextContent();
      const text = textContent.items.map((item: any) => item.str).join(' ');

      pages.push({ imageUrl, text });
    }
  }

  return pages;
};

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, Maximize2, Minimize2, Bookmark, BookOpen } from 'lucide-react';
import { PageData, BookMetadata } from '../types';

interface ReaderProps {
  pages: PageData[];
  metadata: BookMetadata | null;
}

const Reader: React.FC<ReaderProps> = ({ pages, metadata }) => {
  const [currentPage, setCurrentPage] = useState(0);
  const [isSpread, setIsSpread] = useState(window.innerWidth > 1024);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const readerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleResize = () => {
      setIsSpread(window.innerWidth > 1024);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const totalPages = pages.length;

  const goToNext = () => {
    if (isSpread) {
      if (currentPage + 2 < totalPages) setCurrentPage(currentPage + 2);
    } else {
      if (currentPage + 1 < totalPages) setCurrentPage(currentPage + 1);
    }
  };

  const goToPrev = () => {
    if (isSpread) {
      if (currentPage - 2 >= 0) setCurrentPage(currentPage - 2);
    } else {
      if (currentPage - 1 >= 0) setCurrentPage(currentPage - 1);
    }
  };

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      readerRef.current?.requestFullscreen();
      setIsFullScreen(true);
    } else {
      document.exitFullscreen();
      setIsFullScreen(false);
    }
  };

  const renderPage = (index: number, side: 'left' | 'right' | 'single') => {
    if (index < 0 || index >= totalPages) {
      return (
        <div className="w-full h-full bg-slate-100 flex items-center justify-center border-l border-slate-300 shadow-inner">
          <p className="text-slate-400 italic">End of Book</p>
        </div>
      );
    }

    const shadowClass = side === 'left' 
      ? 'shadow-[inset_-10px_0px_10px_-10px_rgba(0,0,0,0.5)] border-r border-slate-300' 
      : 'shadow-[inset_10px_0px_10px_-10px_rgba(0,0,0,0.5)] border-l border-slate-300';

    return (
      <div className={`relative w-full h-full bg-white transition-all duration-500 overflow-hidden ${isSpread ? shadowClass : ''}`}>
        <img 
          src={pages[index].imageUrl} 
          alt={`Page ${index + 1}`} 
          className="w-full h-full object-contain select-none"
        />
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-xs text-slate-400 font-medium">
          {index + 1}
        </div>
      </div>
    );
  };

  return (
    <div ref={readerRef} className="flex flex-col h-full bg-slate-900 text-white overflow-hidden">
      {/* Header Controls */}
      <div className="flex items-center justify-between p-4 bg-slate-800 border-b border-slate-700">
        <div className="flex items-center gap-3">
          <BookOpen className="w-5 h-5 text-indigo-400" />
          <h2 className="text-sm font-semibold truncate max-w-[200px] md:max-w-md">
            {metadata?.title || 'Untitled Document'}
          </h2>
        </div>
        <div className="flex items-center gap-4">
          <span className="text-xs text-slate-400">
            Page {currentPage + 1} of {totalPages}
          </span>
          <button 
            onClick={toggleFullScreen}
            className="p-2 hover:bg-slate-700 rounded-lg transition-colors"
          >
            {isFullScreen ? <Minimize2 className="w-5 h-5" /> : <Maximize2 className="w-5 h-5" />}
          </button>
        </div>
      </div>

      {/* Book Container */}
      <div className="flex-1 relative flex items-center justify-center p-4 md:p-8 overflow-hidden group">
        <div className={`
          relative flex transition-transform duration-700 ease-in-out
          ${isSpread ? 'w-[min(90vw,1200px)] aspect-[1.4/1]' : 'w-[min(85vw,600px)] aspect-[0.7/1]'}
          bg-slate-200 shadow-2xl rounded-sm overflow-hidden border-[12px] border-slate-800
        `}>
          {isSpread ? (
            <>
              <div className="w-1/2 h-full bg-white">
                {renderPage(currentPage, 'left')}
              </div>
              <div className="w-1/2 h-full bg-white">
                {renderPage(currentPage + 1, 'right')}
              </div>
            </>
          ) : (
            <div className="w-full h-full bg-white">
              {renderPage(currentPage, 'single')}
            </div>
          )}

          {/* Spine Highlight */}
          {isSpread && (
            <div className="absolute left-1/2 top-0 bottom-0 w-[1px] bg-black/10 z-10 -translate-x-1/2 shadow-[0_0_15px_rgba(0,0,0,0.5)]" />
          )}
        </div>

        {/* Navigation Overlays */}
        <button 
          onClick={goToPrev}
          disabled={currentPage === 0}
          className={`
            absolute left-4 md:left-10 p-4 rounded-full bg-white/10 hover:bg-white/20 transition-all backdrop-blur-sm
            disabled:opacity-0 disabled:pointer-events-none group-hover:scale-110
          `}
        >
          <ChevronLeft className="w-8 h-8" />
        </button>

        <button 
          onClick={goToNext}
          disabled={currentPage >= totalPages - (isSpread ? 2 : 1)}
          className={`
            absolute right-4 md:right-10 p-4 rounded-full bg-white/10 hover:bg-white/20 transition-all backdrop-blur-sm
            disabled:opacity-0 disabled:pointer-events-none group-hover:scale-110
          `}
        >
          <ChevronRight className="w-8 h-8" />
        </button>
      </div>

      {/* Progress Bar */}
      <div className="bg-slate-800 p-2">
        <div className="max-w-3xl mx-auto flex items-center gap-4">
          <div className="flex-1 h-1.5 bg-slate-700 rounded-full overflow-hidden">
            <div 
              className="h-full bg-indigo-500 transition-all duration-300"
              style={{ width: `${((currentPage + (isSpread ? 2 : 1)) / totalPages) * 100}%` }}
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Reader;

