        `}
        style={{ transformStyle: 'preserve-3d' }}>

          {/* Static Background Pages (The destination) */}
          <div className="absolute inset-0 flex" style={{ transform: 'translateZ(-2px)' }}>
            <div className="w-1/2 h-full bg-white border-r border-slate-200 overflow-hidden">
              {isSpread && direction === 'next' ? (
                <img src={getPageUrl(currentPage)} className="w-full h-full object-contain" alt="" />
              ) : isSpread && direction === 'prev' ? (
                <img src={getPageUrl(currentPage - 2)} className="w-full h-full object-contain" alt="" />
              ) : isSpread ? (
                <img src={getPageUrl(currentPage)} className="w-full h-full object-contain" alt="" />
              ) : null}
            </div>
            <div className="w-1/2 h-full bg-white overflow-hidden">
              {isSpread && direction === 'next' ? (
                <img src={getPageUrl(currentPage + 3)} className="w-full h-full object-contain" alt="" />
              ) : isSpread && direction === 'prev' ? (
                <img src={getPageUrl(currentPage + 1)} className="w-full h-full object-contain" alt="" />
              ) : isSpread ? (
                <img src={getPageUrl(currentPage + 1)} className="w-full h-full object-contain" alt="" />
              ) : null}
            </div>
          </div>

          {/* Flipping Page Component */}
          {isAnimating && isSpread && (
            <div className={`
