            style={{ transformStyle: 'preserve-3d' }}>
              {/* Front side of flipping page */}
              <div className="absolute inset-0 bg-white backface-hidden shadow-[-10px_0_30px_rgba(0,0,0,0.1)] overflow-hidden">
                <img 
                  src={direction === 'next' ? getPageUrl(currentPage + 1)! : getPageUrl(currentPage)!} 
                  className="w-full h-full object-contain" 
                  alt="" 
                />
                <div className="absolute inset-0 bg-gradient-to-r from-black/20 to-transparent pointer-events-none" />
              </div>
              {/* Back side of flipping page */}
              <div className="absolute inset-0 bg-white backface-hidden overflow-hidden" 
                   style={{ transform: 'rotateY(180deg)' }}>
                <img 
                  src={direction === 'next' ? getPageUrl(currentPage + 2)! : getPageUrl(currentPage - 1)!} 
                  className="w-full h-full object-contain scale-x-[-1]" 
                  alt="" 
                />
                <div className="absolute inset-0 bg-gradient-to-l from-black/20 to-transparent pointer-events-none" />
              </div>
            </div>
          )}

          {/* Non-animating Single View / Mobile */}
          {!isSpread && !isAnimating && (
             <div className="w-full h-full bg-white overflow-hidden">
                <img src={getPageUrl(currentPage)!} className="w-full h-full object-contain" alt="" />
             </div>
          )}

          {/* Spine Detail */}
          {isSpread && (
            <div className="absolute left-1/2 top-0 bottom-0 w-[4px] bg-gradient-to-r from-black/30 via-black/10 to-black/30 z-40 -translate-x-1/2" />
          )}
        </div>

        {/* Navigation Buttons */}
        <button 
          onClick={handlePrev}
          disabled={currentPage === 0 || isAnimating}
          className="absolute left-4 md:left-10 p-5 rounded-full bg-white/5 hover:bg-white/10 border border-white/10 transition-all disabled:opacity-0 z-50 group backdrop-blur-sm"
        >
          <ChevronLeft className="w-8 h-8 text-white group-hover:-translate-x-1 transition-transform" />
        </button>

        <button 
          onClick={handleNext}
          disabled={currentPage >= totalPages - (isSpread ? 2 : 1) || isAnimating}
          className="absolute right-4 md:right-10 p-5 rounded-full bg-white/5 hover:bg-white/10 border border-white/10 transition-all disabled:opacity-0 z-50 group backdrop-blur-sm"
