            onClick={handlePrev}
            className={`w-1/2 h-full pointer-events-auto cursor-w-resize ${currentPage === 0 || isAnimating ? 'cursor-default' : ''}`}
            title="Previous Page"
          />
          <div 
            onClick={handleNext}
            className={`w-1/2 h-full pointer-events-auto cursor-e-resize ${currentPage >= totalPages - (isSpread ? 2 : 1) || isAnimating ? 'cursor-default' : ''}`}
            title="Next Page"
          />
        </div>

        {/* The Book Container */}
        <div className={`
          relative flex transition-all duration-1000 cubic-bezier(0.2, 0.8, 0.2, 1)
          ${isSpread ? 'w-[min(90vw,1200px)] aspect-[1.414/1]' : 'w-[min(88vw,550px)] aspect-[0.707/1]'}
          ${isAnimating ? 'scale-[0.96] brightness-90' : 'scale-100 brightness-100'}
        `}
        style={{ transformStyle: 'preserve-3d' }}>

          {/* Base Layer: Warm Paper Texture underneath */}
          <div className="absolute inset-0 flex z-0 rounded-sm overflow-hidden shadow-[0_40px_100px_-20px_rgba(0,0,0,0.8)]" style={{ transform: 'translateZ(-5px)' }}>
             <div className="w-1/2 h-full bg-[#fdfcf9] border-r border-black/5" />
             <div className="w-1/2 h-full bg-[#fdfcf9]" />
          </div>

          {/* 1. Underlying Destination Pages */}
          <div className="absolute inset-0 flex z-0" style={{ transform: 'translateZ(-2px)' }}>
            <div className="w-1/2 h-full bg-[#fdfcf9] border-r border-black/5 overflow-hidden">
              {direction === 'prev' ? renderPageImage(currentPage - 2) : renderPageImage(currentPage)}
            </div>
            <div className="w-1/2 h-full bg-[#fdfcf9] overflow-hidden">
              {direction === 'next' ? renderPageImage(currentPage + 3) : renderPageImage(currentPage + 1)}
            </div>
          </div>

          {/* 2. Flipping Page (Animated) */}
          {isAnimating && isSpread && (
            <div className={`
              absolute top-0 bottom-0 w-1/2 z-30
              ${direction === 'next' ? 'right-0 origin-left animate-natural-flip-next' : 'left-0 origin-right animate-natural-flip-prev'}
            `}
            style={{ transformStyle: 'preserve-3d' }}>

              {/* Front side (Current page turning away) */}
              <div className="absolute inset-0 bg-[#fdfcf9] backface-hidden overflow-hidden shadow-2xl">
                {direction === 'next' ? renderPageImage(currentPage + 1) : renderPageImage(currentPage)}
                <div className="absolute inset-0 bg-gradient-to-r from-black/10 via-transparent to-black/5" />
              </div>

              {/* Back side (Target page arriving) */}
              <div className="absolute inset-0 bg-[#fdfcf9] backface-hidden overflow-hidden" 
                   style={{ transform: 'rotateY(180deg)' }}>
                <div className="w-full h-full scale-x-[-1]">
                  {direction === 'next' ? renderPageImage(currentPage + 2) : renderPageImage(currentPage - 1)}
                </div>
                <div className="absolute inset-0 bg-gradient-to-l from-black/15 via-transparent to-black/5" />
              </div>
            </div>
          )}

          {/* 3. Static Visible Overlay (When idle) */}
          {!isAnimating && (
            <div className="absolute inset-0 flex z-10 transition-opacity duration-300">
              {isSpread ? (
                <>
                  <div className="w-1/2 h-full bg-[#fdfcf9] border-r border-black/10 overflow-hidden shadow-inner">
                    {renderPageImage(currentPage)}
                    <div className="absolute inset-0 bg-gradient-to-r from-black/5 via-transparent to-transparent pointer-events-none" />
                  </div>
                  <div className="w-1/2 h-full bg-[#fdfcf9] overflow-hidden shadow-inner">
                    {renderPageImage(currentPage + 1)}
                    <div className="absolute inset-0 bg-gradient-to-l from-black/5 via-transparent to-transparent pointer-events-none" />
                  </div>
                </>
              ) : (
                <div className="w-full h-full bg-[#fdfcf9] shadow-2xl animate-soft-fade">
                  {renderPageImage(currentPage)}
                </div>
              )}
            </div>
          )}

          {/* Visual Spine */}
          {isSpread && (
            <div className="absolute left-1/2 top-0 bottom-0 w-[10px] -translate-x-1/2 z-40
              bg-gradient-to-r from-black/40 via-black/5 to-black/40" />
          )}

          {/* Book Edge Details */}
          <div className="absolute -right-1 top-[2%] bottom-[2%] w-1 bg-slate-200/20 rounded-r z-0" />
          <div className="absolute -left-1 top-[2%] bottom-[2%] w-1 bg-slate-200/20 rounded-l z-0" />
        </div>

        {/* Traditional Arrows (Hidden on desktop, useful for mobile) */}
        <div className="absolute bottom-10 flex gap-4 md:hidden z-50">
           <button onClick={handlePrev} className="p-4 bg-white/10 rounded-full border border-white/20"><ChevronLeft/></button>
           <button onClick={handleNext} className="p-4 bg-white/10 rounded-full border border-white/20"><ChevronRight/></button>
        </div>
      </div>

      {/* Refined Progress Bar */}
      <div className="bg-black/60 backdrop-blur-xl border-t border-white/5 px-8 py-8">
        <div className="max-w-4xl mx-auto">
          <div className="flex items-end justify-between mb-4">
             <div className="flex flex-col">
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em]">Reading Status</span>
               <span className="text-sm font-bold text-indigo-300 mt-1">
                 {Math.round(((currentPage + (isSpread ? 2 : 1)) / totalPages) * 100)}% Journey Completed
               </span>
             </div>
             <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase">
                <span>P. {currentPage + 1}</span>
                <div className="w-1 h-1 bg-slate-700 rounded-full" />
                <span>VOL. 1</span>
             </div>
          </div>
          <div className="relative h-1.5 w-full bg-slate-800/50 rounded-full overflow-hidden">
            <div 
              className="h-full bg-gradient-to-r from-indigo-600 via-indigo-400 to-indigo-500 transition-all duration-1000 cubic-bezier(0.2, 0.8, 0.2, 1) relative"
              style={{ width: `${((currentPage + (isSpread ? 2 : 1)) / totalPages) * 100}%` }}
            >
              <div className="absolute right-0 top-0 bottom-0 w-20 bg-gradient-to-r from-transparent to-white/20 blur-sm" />
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .perspective-4000 {
          perspective: 4000px;
        }
        .backface-hidden {
          backface-visibility: hidden;
          -webkit-backface-visibility: hidden;
        }
        .cubic-bezier {
          transition-timing-function: cubic-bezier(0.23, 1, 0.32, 1);
        }

        @keyframes natural-flip-next {
          0% { 
            transform: rotateY(0deg) scale(1) rotateX(0deg); 
            filter: brightness(1);
          }
          30% {
             transform: rotateY(-50deg) scale(1.05) rotateX(1deg);
          }
          100% { 
            transform: rotateY(-180deg) scale(1) rotateX(0deg);
            filter: brightness(1.05);
          }
        }

        @keyframes natural-flip-prev {
          0% { 
            transform: rotateY(0deg) scale(1) rotateX(0deg); 
            filter: brightness(1);
          }
          30% {
             transform: rotateY(50deg) scale(1.05) rotateX(-1deg);
          }
          100% { 
            transform: rotateY(180deg) scale(1) rotateX(0deg); 
            filter: brightness(1.05);
          }
        }

        @keyframes soft-fade {
          from { opacity: 0; filter: blur(4px); }
          to { opacity: 1; filter: blur(0); }
        }

        .animate-natural-flip-next {
          animation: natural-flip-next 0.8s cubic-bezier(0.4, 0, 0.2, 1) forwards;
        }

        .animate-natural-flip-prev {
          animation: natural-flip-prev 0.8s cubic-bezier(0.4, 0, 0.2, 1) forwards;
        }

        .animate-soft-fade {
          animation: soft-fade 0.5s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default Reader;

import React, { useState, useCallback } from 'react';
