);

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ChevronLeft, ChevronRight, Maximize2, Minimize2, BookOpen, Sparkles, Search, MousePointer2 } from 'lucide-react';
import { PageData, BookMetadata } from '../types';

interface ReaderProps {
  pages: PageData[];
  metadata: BookMetadata | null;
}

const Reader: React.FC<ReaderProps> = ({ pages, metadata }) => {
  const [currentPage, setCurrentPage] = useState(0);
  const [isSpread, setIsSpread] = useState(window.innerWidth > 1024);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'next' | 'prev' | null>(null);

  // Zoom & Pan State
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [lastMousePos, setLastMousePos] = useState({ x: 0, y: 0 });

  const readerRef = useRef<HTMLDivElement>(null);
  const bookStageRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleResize = () => {
      setIsSpread(window.innerWidth > 1024);
      // Reset zoom on resize to prevent layout breaking
      setScale(1);
      setPan({ x: 0, y: 0 });
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const totalPages = pages.length;

  const handleNext = useCallback(() => {
    if (isAnimating) return;
    const step = isSpread ? 2 : 1;
    if (currentPage + step < totalPages) {
      setDirection('next');
      setIsAnimating(true);
      setTimeout(() => {
        setCurrentPage(prev => prev + step);
        setIsAnimating(false);
        setDirection(null);
      }, 800);
    }
  }, [isAnimating, isSpread, currentPage, totalPages]);

  const handlePrev = useCallback(() => {
    if (isAnimating) return;
    const step = isSpread ? 2 : 1;
    if (currentPage - step >= 0) {
      setDirection('prev');
      setIsAnimating(true);
      setTimeout(() => {
        setCurrentPage(prev => prev - step);
        setIsAnimating(false);
        setDirection(null);
      }, 800);
    }
  }, [isAnimating, isSpread, currentPage]);

  // Mouse Wheel Zoom
  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) return; // Allow browser zoom
    e.preventDefault();
    const delta = e.deltaY > 0 ? -0.1 : 0.1;
    const newScale = Math.min(Math.max(scale + delta, 1), 3);
    setScale(newScale);
    if (newScale === 1) setPan({ x: 0, y: 0 });
  };

  // Drag to Pan
  const handleMouseDown = (e: React.MouseEvent) => {
    if (scale <= 1) return;
    setIsDragging(true);
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || scale <= 1) return;
    const dx = e.clientX - lastMousePos.x;
    const dy = e.clientY - lastMousePos.y;
    setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      readerRef.current?.requestFullscreen();
      setIsFullScreen(true);
    } else {
      document.exitFullscreen();
      setIsFullScreen(false);
    }
  };

  const getPageUrl = (index: number) => {
    if (index < 0 || index >= totalPages) return null;
    return pages[index].imageUrl;
  };

  const renderPageImage = (index: number) => {
    const url = getPageUrl(index);
    if (!url) return <div className="w-full h-full bg-[#fdfcf9]" />;
    return <img src={url} className="w-full h-full object-contain pointer-events-none select-none" alt="" />;
  };

  return (
    <div 
      ref={readerRef} 
      className="flex flex-col h-full bg-[#08090b] text-white overflow-hidden font-inter selection:bg-indigo-500/30 touch-none"
      onWheel={handleWheel}
    >
      {/* Elegant Header */}
      <div className="flex items-center justify-between px-6 py-4 bg-black/40 backdrop-blur-2xl border-b border-white/5 z-[60]">
        <div className="flex items-center gap-5">
          <div className="relative">
            <div className="absolute inset-0 bg-indigo-500/20 blur-xl rounded-full" />
            <div className="relative p-2.5 bg-white/5 rounded-xl border border-white/10">
              <BookOpen className="w-5 h-5 text-indigo-300" />
            </div>
          </div>
          <div className="flex flex-col">
            <h2 className="text-sm font-semibold truncate max-w-[150px] md:max-w-md text-slate-100 book-font italic tracking-wide">
              {metadata?.title || 'Untitled Archive'}
            </h2>
            <div className="flex items-center gap-2 mt-0.5">
              <span className="text-[9px] text-slate-500 font-black uppercase tracking-[0.2em]">Authored By</span>
              <span className="text-[10px] text-indigo-400 font-bold uppercase tracking-wider">
                {metadata?.author || 'Unknown'}
              </span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="hidden sm:flex items-center gap-3 px-4 py-2 bg-white/5 rounded-full border border-white/10">
            <Search className="w-3 h-3 text-slate-500" />
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
              Zoom: {Math.round(scale * 100)}%
            </span>
          </div>
          <button 
            onClick={toggleFullScreen}
            className="p-2.5 hover:bg-white/10 rounded-full transition-all active:scale-95 text-slate-400 hover:text-white"
          >
            {isFullScreen ? <Minimize2 className="w-5 h-5" /> : <Maximize2 className="w-5 h-5" />}
          </button>
        </div>
      </div>

      {/* Main 3D Stage with Zoom/Pan Support */}
      <div 
        className={`flex-1 relative flex items-center justify-center p-8 md:p-20 overflow-hidden perspective-4000 ${scale > 1 ? (isDragging ? 'cursor-grabbing' : 'cursor-grab') : ''}`}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
      >
        {/* Navigation Zones: Click areas for page turns */}
        <div className="absolute inset-0 z-[55] flex pointer-events-none">
          <div 
            onClick={handlePrev}
            className={`w-1/2 h-full pointer-events-auto cursor-w-resize ${currentPage === 0 || isAnimating ? 'cursor-default' : ''}`}
          />
          <div 
            onClick={handleNext}
            className={`w-1/2 h-full pointer-events-auto cursor-e-resize ${currentPage >= totalPages - (isSpread ? 2 : 1) || isAnimating ? 'cursor-default' : ''}`}
          />
        </div>

        {/* The Animated Book Wrapper */}
        <div 
          ref={bookStageRef}
          className="relative transition-transform duration-300 ease-out will-change-transform"
          style={{ 
            transform: `scale(${scale}) translate(${pan.x / scale}px, ${pan.y / scale}px)`,
            transformStyle: 'preserve-3d'
          }}
        >
          <div className={`
            relative flex transition-all duration-1000 cubic-bezier(0.2, 0.8, 0.2, 1)
            ${isSpread ? 'w-[min(90vw,1200px)] aspect-[1.414/1]' : 'w-[min(88vw,550px)] aspect-[0.707/1]'}
            ${isAnimating ? 'brightness-90 scale-[0.98]' : 'brightness-100 scale-100'}
          `}
          style={{ transformStyle: 'preserve-3d' }}>

            {/* DESTINATION LAYER (Revealed during flip) */}
            <div className="absolute inset-0 flex z-0 rounded-sm overflow-hidden shadow-[0_40px_100px_-20px_rgba(0,0,0,0.8)]" style={{ transform: 'translateZ(-10px)' }}>
               <div className="w-1/2 h-full bg-[#fdfcf9] border-r border-black/5 overflow-hidden">
                 {/* As we flip back, we see the previous page underneath */}
                 {isAnimating && direction === 'prev' ? renderPageImage(currentPage - 2) : renderPageImage(currentPage)}
               </div>
               <div className="w-1/2 h-full bg-[#fdfcf9] overflow-hidden">
                 {/* As we flip next, we see the next spread underneath */}
                 {isAnimating && direction === 'next' ? renderPageImage(currentPage + 3) : renderPageImage(currentPage + 1)}
               </div>
            </div>

            {/* FLIPPING LEAF (The moving part) */}
            {isAnimating && isSpread && (
              <div className={`
                absolute top-0 bottom-0 w-1/2 z-[30]
                ${direction === 'next' ? 'right-0 origin-left animate-natural-flip-next' : 'left-0 origin-right animate-natural-flip-prev'}
              `}
              style={{ transformStyle: 'preserve-3d' }}>

                {/* Front side (Outgoing page) */}
                <div className="absolute inset-0 bg-[#fdfcf9] backface-hidden overflow-hidden shadow-2xl">
                  {direction === 'next' ? renderPageImage(currentPage + 1) : renderPageImage(currentPage)}
                  <div className="absolute inset-0 bg-gradient-to-r from-black/10 via-transparent to-black/5" />
                </div>

                {/* Back side (Incoming page) */}
                <div className="absolute inset-0 bg-[#fdfcf9] backface-hidden overflow-hidden" 
                     style={{ transform: 'rotateY(180deg)' }}>
                  <div className="w-full h-full scale-x-[-1]">
                    {direction === 'next' ? renderPageImage(currentPage + 2) : renderPageImage(currentPage - 1)}
                  </div>
                  <div className="absolute inset-0 bg-gradient-to-l from-black/15 via-transparent to-black/5" />
                </div>
              </div>
            )}

            {/* STATIC VISIBLE OVERLAY (Idle state) */}
            {!isAnimating && (
              <div className="absolute inset-0 flex z-10">
                {isSpread ? (
                  <>
                    <div className="w-1/2 h-full bg-[#fdfcf9] border-r border-black/10 overflow-hidden shadow-inner">
                      {renderPageImage(currentPage)}
                      <div className="absolute inset-0 bg-gradient-to-r from-black/5 via-transparent to-transparent pointer-events-none" />
                    </div>
                    <div className="w-1/2 h-full bg-[#fdfcf9] overflow-hidden shadow-inner">
                      {renderPageImage(currentPage + 1)}
                      <div className="absolute inset-0 bg-gradient-to-l from-black/5 via-transparent to-transparent pointer-events-none" />
                    </div>
                  </>
                ) : (
                  <div className="w-full h-full bg-[#fdfcf9] shadow-2xl">
                    {renderPageImage(currentPage)}
                  </div>
                )}
              </div>
            )}

            {/* Visual Spine & Shadows */}
            {isSpread && (
              <div className="absolute left-1/2 top-0 bottom-0 w-[12px] -translate-x-1/2 z-40
                bg-gradient-to-r from-black/40 via-black/5 to-black/40 shadow-inner opacity-60" />
            )}

            {/* Book Thick Edge (Visual stack of pages) */}
            <div className="absolute -right-2 top-[2%] bottom-[2%] w-2 bg-slate-200/20 border-r border-white/5 rounded-r-lg z-0" />
            <div className="absolute -left-2 top-[2%] bottom-[2%] w-2 bg-slate-200/20 border-l border-white/5 rounded-l-lg z-0" />
          </div>
        </div>

        {/* Helpful Interaction Tip */}
        {scale === 1 && !isAnimating && (
          <div className="absolute bottom-10 left-1/2 -translate-x-1/2 px-4 py-2 bg-white/5 backdrop-blur-md rounded-full border border-white/10 opacity-40 hover:opacity-100 transition-opacity flex items-center gap-2 pointer-events-none">
            <MousePointer2 className="w-3 h-3 text-indigo-400" />
            <span className="text-[9px] font-bold uppercase tracking-widest text-slate-300">Scroll to Zoom • Drag to Pan</span>
          </div>
        )}
      </div>

      {/* Modern Progress Navigation */}
      <div className="bg-black/80 backdrop-blur-3xl border-t border-white/5 px-8 py-6 z-[60]">
        <div className="max-w-4xl mx-auto">
          <div className="flex items-end justify-between mb-3">
             <div className="flex flex-col">
               <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.3em]">Manuscript Progress</span>
               <span className="text-sm font-bold text-indigo-300 mt-1 flex items-center gap-2">
                 <Sparkles className="w-3 h-3" />
                 {Math.round(((currentPage + (isSpread ? 2 : 1)) / totalPages) * 100)}% Journeyed
               </span>
             </div>
             <div className="flex items-center gap-4">
                <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                  <span>P. {currentPage + 1}</span>
                  <div className="w-1 h-1 bg-slate-700 rounded-full" />
                  <span>TOTAL {totalPages}</span>
                </div>
                <div className="flex gap-2">
                  <button onClick={handlePrev} disabled={currentPage === 0 || isAnimating} className="p-2 bg-white/5 border border-white/10 rounded-lg hover:bg-white/10 disabled:opacity-30"><ChevronLeft className="w-4 h-4" /></button>
                  <button onClick={handleNext} disabled={currentPage >= totalPages - (isSpread ? 2 : 1) || isAnimating} className="p-2 bg-white/5 border border-white/10 rounded-lg hover:bg-white/10 disabled:opacity-30"><ChevronRight className="w-4 h-4" /></button>
                </div>
             </div>
          </div>
          <div className="relative h-1 w-full bg-slate-800/50 rounded-full overflow-hidden">
            <div 
              className="h-full bg-gradient-to-r from-indigo-600 via-indigo-400 to-indigo-500 transition-all duration-1000 cubic-bezier(0.2, 0.8, 0.2, 1) relative"
              style={{ width: `${((currentPage + (isSpread ? 2 : 1)) / totalPages) * 100}%` }}
            >
