import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ChevronLeft, ChevronRight, Maximize2, Minimize2, BookOpen, Sparkles, Search, MousePointer2, ArrowLeft, ArrowRight } from 'lucide-react';
import { PageData, BookMetadata } from '../types';

interface ReaderProps {
  pages: PageData[];
  metadata: BookMetadata | null;
}

const Reader: React.FC<ReaderProps> = ({ pages, metadata }) => {
  const [currentPage, setCurrentPage] = useState(0);
  const [isSpread, setIsSpread] = useState(window.innerWidth > 1024);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'next' | 'prev' | null>(null);

  // Zoom & Pan State
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [lastMousePos, setLastMousePos] = useState({ x: 0, y: 0 });

  const readerRef = useRef<HTMLDivElement>(null);
  const bookStageRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleResize = () => {
      setIsSpread(window.innerWidth > 1024);
      setScale(1);
      setPan({ x: 0, y: 0 });
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const totalPages = pages.length;

  const handleNext = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating) return;
    const step = isSpread ? 2 : 1;
    if (currentPage + step < totalPages) {
      setDirection('next');
      setIsAnimating(true);
      setTimeout(() => {
        setCurrentPage(prev => prev + step);
        setIsAnimating(false);
        setDirection(null);
      }, 800);
    }
  }, [isAnimating, isSpread, currentPage, totalPages]);

  const handlePrev = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating) return;
    const step = isSpread ? 2 : 1;
    if (currentPage - step >= 0) {
      setDirection('prev');
      setIsAnimating(true);
      setTimeout(() => {
        setCurrentPage(prev => prev - step);
        setIsAnimating(false);
        setDirection(null);
      }, 800);
    }
  }, [isAnimating, isSpread, currentPage]);

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) return; 
    e.preventDefault();
    const delta = e.deltaY > 0 ? -0.15 : 0.15;
    const newScale = Math.min(Math.max(scale + delta, 1), 3);
    setScale(newScale);
    if (newScale === 1) setPan({ x: 0, y: 0 });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (scale <= 1) return;
    setIsDragging(true);
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || scale <= 1) return;
    const dx = e.clientX - lastMousePos.x;
    const dy = e.clientY - lastMousePos.y;
    setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      readerRef.current?.requestFullscreen();
      setIsFullScreen(true);
    } else {
      document.exitFullscreen();
      setIsFullScreen(false);
    }
  };

  const renderPageImage = (index: number) => {
    if (index < 0 || index >= totalPages) return <div className="w-full h-full bg-[#fdfcf9]" />;
    const url = pages[index].imageUrl;
    /**
     * High-quality rendering needs optimized image display.
     * Changed 'high-quality' to 'auto' to fix TypeScript assignment error.
     */
    return (
      <img 
        src={url} 
        className="w-full h-full object-contain pointer-events-none select-none transition-opacity duration-300" 
        style={{ imageRendering: 'auto' }}
        alt="" 
      />
    );
  };

