    setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      readerRef.current?.requestFullscreen();
      setIsFullScreen(true);
    } else {
      document.exitFullscreen();
      setIsFullScreen(false);
    }
  };

  const renderPageImage = (index: number) => {
    if (index < 0 || index >= totalPages) return <div className="w-full h-full bg-[#fdfcf9]" />;
    const url = pages[index].imageUrl;
    return (
      <img 
        src={url} 
        className="w-full h-full object-contain pointer-events-none select-none" 
        style={{ imageRendering: 'auto' }}
        alt="" 
      />
    );
  };

  return (
    <div 
      ref={readerRef} 
      className="flex flex-col h-full bg-[#08090b] text-white overflow-hidden font-inter selection:bg-indigo-500/30 touch-none"
      onWheel={handleWheel}
    >
      {/* Header */}
      <div className="flex items-center justify-between px-6 py-4 bg-black/40 backdrop-blur-2xl border-b border-white/5 z-[60]">
        <div className="flex items-center gap-5">
          <div className="relative">
            <div className="absolute inset-0 bg-indigo-500/20 blur-xl rounded-full" />
            <div className="relative p-2.5 bg-white/5 rounded-xl border border-white/10">
              <BookOpen className="w-5 h-5 text-indigo-300" />
            </div>
          </div>
          <div className="flex flex-col">
            <h2 className="text-sm font-semibold truncate max-w-[150px] md:max-w-md text-slate-100 book-font italic tracking-wide">
              {metadata?.title || 'Untitled Archive'}
            </h2>
            <div className="flex items-center gap-2 mt-0.5">
              <span className="text-[9px] text-slate-500 font-black uppercase tracking-[0.2em]">Authored By</span>
              <span className="text-[10px] text-indigo-400 font-bold uppercase tracking-wider">
                {metadata?.author || 'Unknown'}
              </span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="hidden sm:flex items-center gap-3 px-4 py-2 bg-white/5 rounded-full border border-white/10">
            <Search className="w-3 h-3 text-slate-500" />
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
              Zoom: {Math.round(scale * 100)}%
            </span>
          </div>
          <button 
            onClick={toggleFullScreen}
            className="p-2.5 hover:bg-white/10 rounded-full transition-all active:scale-95 text-slate-400 hover:text-white"
          >
            {isFullScreen ? <Minimize2 className="w-5 h-5" /> : <Maximize2 className="w-5 h-5" />}
          </button>
        </div>
      </div>

      {/* Main Stage */}
      <div 
        className={`flex-1 relative flex items-center justify-center p-8 md:p-14 overflow-hidden perspective-4000 ${scale > 1 ? (isDragging ? 'cursor-grabbing' : 'cursor-grab') : ''}`}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
      >
        <div 
          ref={bookStageRef}
          className="relative transition-transform duration-300 ease-out will-change-transform"
          style={{ 
            transform: `scale(${scale}) translate(${pan.x / scale}px, ${pan.y / scale}px)`,
            transformStyle: 'preserve-3d'
          }}
        >
          <div className={`
            relative flex transition-all duration-1200 cubic-bezier(0.2, 0.8, 0.2, 1)
            ${isSpread ? 'w-[min(90vw,1200px)] aspect-[1.414/1]' : 'w-[min(88vw,550px)] aspect-[0.707/1]'}
            ${isAnimating ? 'brightness-95 scale-[0.99]' : 'brightness-100 scale-100'}
          `}
          style={{ transformStyle: 'preserve-3d' }}>

            {/* DESTINATION LAYER */}
            <div className="absolute inset-0 flex z-0 rounded-sm overflow-hidden shadow-[0_40px_100px_-20px_rgba(0,0,0,0.8)]" style={{ transform: 'translateZ(-10px)' }}>
               <div className="w-1/2 h-full bg-[#fdfcf9] border-r border-black/5 overflow-hidden">
                 {isAnimating && direction === 'prev' ? renderPageImage(currentPage - 2) : renderPageImage(currentPage)}
               </div>
               <div className="w-1/2 h-full bg-[#fdfcf9] overflow-hidden">
                 {isAnimating && direction === 'next' ? renderPageImage(currentPage + 3) : renderPageImage(currentPage + 1)}
               </div>
            </div>

            {/* FLIPPING LEAF (The screen changes as it turns because we show the front then back) */}
            {isAnimating && isSpread && (
              <div className={`
                absolute top-0 bottom-0 w-1/2 z-[30]
                ${direction === 'next' ? 'right-0 origin-left animate-natural-flip-next' : 'left-0 origin-right animate-natural-flip-prev'}
              `}
              style={{ transformStyle: 'preserve-3d' }}>

                {/* Front side (Outgoing page - visible at start of turn) */}
                <div className="absolute inset-0 bg-[#fdfcf9] backface-hidden overflow-hidden shadow-2xl">
                  {direction === 'next' ? renderPageImage(currentPage + 1) : renderPageImage(currentPage)}
                  <div className="absolute inset-0 bg-gradient-to-r from-black/20 via-transparent to-black/5" />
                </div>

                {/* Back side (Incoming page - revealed as it completes the turn) */}
                <div className="absolute inset-0 bg-[#fdfcf9] backface-hidden overflow-hidden" 
                     style={{ transform: 'rotateY(180deg)' }}>
                  <div className="w-full h-full scale-x-[-1]">
                    {direction === 'next' ? renderPageImage(currentPage + 2) : renderPageImage(currentPage - 1)}
                  </div>
                  <div className="absolute inset-0 bg-gradient-to-l from-black/20 via-transparent to-black/5" />
                </div>
              </div>
            )}

            {/* IDLE OVERLAY */}
            {!isAnimating && (
              <div className="absolute inset-0 flex z-10">
                {isSpread ? (
                  <>
                    <div className="w-1/2 h-full bg-[#fdfcf9] border-r border-black/10 overflow-hidden shadow-inner relative">
                      {renderPageImage(currentPage)}
                      <div className="absolute inset-0 bg-gradient-to-r from-black/5 via-transparent to-transparent pointer-events-none" />
                    </div>
                    <div className="w-1/2 h-full bg-[#fdfcf9] overflow-hidden shadow-inner relative">
                      {renderPageImage(currentPage + 1)}
                      <div className="absolute inset-0 bg-gradient-to-l from-black/5 via-transparent to-transparent pointer-events-none" />
                    </div>
                  </>
                ) : (
                  <div className="w-full h-full bg-[#fdfcf9] shadow-2xl">
                    {renderPageImage(currentPage)}
                  </div>
                )}
              </div>
            )}

            {/* Corner Navigation Triggers (Refined, Discreet, Reactive) */}
            {!isAnimating && (
              <div className="absolute inset-0 z-[50] pointer-events-none">
                {/* Previous Corner (Bottom Left) */}
                {currentPage > 0 && (
                  <div 
                    onClick={handlePrev}
                    className="absolute bottom-0 left-0 w-32 h-32 pointer-events-auto cursor-pointer group"
                    title="Previous Page"
                  >
                    {/* Tiny Triangle with Arrow - Activated by nearby mouse */}
                    <div className="absolute bottom-4 left-4 p-2 bg-indigo-600/60 rounded-full border border-white/20 backdrop-blur-md opacity-20 group-hover:opacity-100 group-hover:bg-indigo-500 group-hover:scale-110 group-active:scale-95 transition-all duration-300 shadow-xl">
                      <ArrowLeft className="w-4 h-4 text-white" />
                    </div>
                    {/* Visual Fold Hint */}
                    <div className="absolute bottom-0 left-0 w-0 h-0 border-t-[30px] border-t-transparent border-l-[30px] border-l-indigo-500/10 group-hover:border-l-indigo-500/40 transition-all duration-300" />
                  </div>
                )}

                {/* Next Corner (Bottom Right) */}
                {currentPage < totalPages - (isSpread ? 2 : 1) && (
                  <div 
                    onClick={handleNext}
                    className="absolute bottom-0 right-0 w-32 h-32 pointer-events-auto cursor-pointer group"
                    title="Next Page"
                  >
                    {/* Tiny Triangle with Arrow - Activated by nearby mouse */}
                    <div className="absolute bottom-4 right-4 p-2 bg-indigo-600/60 rounded-full border border-white/20 backdrop-blur-md opacity-20 group-hover:opacity-100 group-hover:bg-indigo-500 group-hover:scale-110 group-active:scale-95 transition-all duration-300 shadow-xl">
                      <ArrowRight className="w-4 h-4 text-white" />
                    </div>
                    {/* Visual Fold Hint */}
                    <div className="absolute bottom-0 right-0 w-0 h-0 border-t-[30px] border-t-transparent border-r-[30px] border-r-indigo-500/10 group-hover:border-r-indigo-500/40 transition-all duration-300" />
                  </div>
                )}
              </div>
            )}

            {/* Visual Spine */}
            {isSpread && (
              <div className="absolute left-1/2 top-0 bottom-0 w-[14px] -translate-x-1/2 z-40
                bg-gradient-to-r from-black/50 via-black/10 to-black/50 shadow-inner opacity-70" />
            )}

            <div className="absolute -right-2 top-[1%] bottom-[1%] w-2 bg-slate-300/30 border-r border-white/5 rounded-r-lg z-0" />
            <div className="absolute -left-2 top-[1%] bottom-[1%] w-2 bg-slate-300/30 border-l border-white/5 rounded-l-lg z-0" />
          </div>
        </div>

        {/* Tip */}
        {scale === 1 && !isAnimating && (
          <div className="absolute bottom-8 left-1/2 -translate-x-1/2 px-4 py-2 bg-white/5 backdrop-blur-md rounded-full border border-white/10 opacity-20 hover:opacity-100 transition-opacity flex items-center gap-3 pointer-events-none">
            <MousePointer2 className="w-3 h-3 text-indigo-400" />
            <span className="text-[9px] font-black uppercase tracking-[0.2em] text-slate-300">Zoom Wheel • Drag Pan • Corner Tap</span>
          </div>
        )}
      </div>

      {/* Footer Navigation */}
      <div className="bg-black/90 backdrop-blur-4xl border-t border-white/5 px-8 py-6 z-[60]">
        <div className="max-w-4xl mx-auto">
          <div className="flex items-end justify-between mb-3">
             <div className="flex flex-col">
               <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.4em]">Folio Progress</span>
               <span className="text-sm font-bold text-indigo-300 mt-1 flex items-center gap-2">
                 <Sparkles className="w-4 h-4" />
                 {Math.round(((currentPage + (isSpread ? 2 : 1)) / totalPages) * 100)}% Consumed
               </span>
             </div>
             <div className="flex items-center gap-5">
                <div className="flex items-center gap-2 text-[11px] font-bold text-slate-400 uppercase tracking-[0.2em]">
                  <span>P. {currentPage + 1}</span>
                  <div className="w-1.5 h-1.5 bg-slate-800 rounded-full" />
                  <span>TOTAL {totalPages}</span>
                </div>
                <div className="flex gap-2.5">
                  <button onClick={handlePrev} disabled={currentPage === 0 || isAnimating} className="p-3 bg-white/5 border border-white/10 rounded-xl hover:bg-white/10 active:scale-95 disabled:opacity-20 transition-all"><ChevronLeft className="w-5 h-5" /></button>
                  <button onClick={handleNext} disabled={currentPage >= totalPages - (isSpread ? 2 : 1) || isAnimating} className="p-3 bg-white/5 border border-white/10 rounded-xl hover:bg-white/10 active:scale-95 disabled:opacity-20 transition-all"><ChevronRight className="w-5 h-5" /></button>
                </div>
             </div>
          </div>
          <div className="relative h-1.5 w-full bg-slate-900 rounded-full overflow-hidden shadow-inner">
            <div 
              className="h-full bg-gradient-to-r from-indigo-700 via-indigo-500 to-indigo-600 transition-all duration-1200 cubic-bezier(0.2, 0.8, 0.2, 1) relative"
              style={{ width: `${((currentPage + (isSpread ? 2 : 1)) / totalPages) * 100}%` }}
            >
              <div className="absolute right-0 top-0 bottom-0 w-24 bg-gradient-to-r from-transparent to-white/30 blur-md" />
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .perspective-4000 { perspective: 4000px; }
        .backface-hidden { backface-visibility: hidden; -webkit-backface-visibility: hidden; }
        .backdrop-blur-4xl { backdrop-filter: blur(80px); }

        @keyframes natural-flip-next {
          0% { transform: rotateY(0deg) scale(1) rotateX(0deg); filter: brightness(1); }
          50% { transform: rotateY(-90deg) scale(1.15) rotateX(4deg); filter: brightness(1.25); }
          100% { transform: rotateY(-180deg) scale(1) rotateX(0deg); filter: brightness(1.1); }
        }

        @keyframes natural-flip-prev {
          0% { transform: rotateY(0deg) scale(1) rotateX(0deg); filter: brightness(1); }
          50% { transform: rotateY(90deg) scale(1.15) rotateX(-4deg); filter: brightness(1.25); }
          100% { transform: rotateY(180deg) scale(1) rotateX(0deg); filter: brightness(1.1); }
        }

        .animate-natural-flip-next { 
          animation: natural-flip-next 1.2s cubic-bezier(0.4, 0, 0.2, 1) forwards; 
        }
        .animate-natural-flip-prev { 
          animation: natural-flip-prev 1.2s cubic-bezier(0.4, 0, 0.2, 1) forwards; 
        }
      `}</style>
    </div>
  );
};

export default Reader;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ChevronLeft, ChevronRight, Maximize2, Minimize2, BookOpen, Sparkles, Search, MousePointer2, ArrowLeft, ArrowRight } from 'lucide-react';
import { PageData, BookMetadata } from '../types';

interface ReaderProps {
  pages: PageData[];
  metadata: BookMetadata | null;
}

const Reader: React.FC<ReaderProps> = ({ pages, metadata }) => {
  const [currentPage, setCurrentPage] = useState(0);
  const [isSpread, setIsSpread] = useState(window.innerWidth > 1024);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'next' | 'prev' | null>(null);

  // Zoom & Pan State
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [lastMousePos, setLastMousePos] = useState({ x: 0, y: 0 });

  const readerRef = useRef<HTMLDivElement>(null);
  const bookStageRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleResize = () => {
      setIsSpread(window.innerWidth > 1024);
      setScale(1);
      setPan({ x: 0, y: 0 });
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const totalPages = pages.length;

  const FLIP_DURATION = 1500; // 1.5 seconds for a luxurious, deliberate flip

  const handleNext = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating) return;
    const step = isSpread ? 2 : 1;
    if (currentPage + step < totalPages) {
      setDirection('next');
      setIsAnimating(true);
      setTimeout(() => {
        setCurrentPage(prev => prev + step);
        setIsAnimating(false);
        setDirection(null);
      }, FLIP_DURATION);
    }
  }, [isAnimating, isSpread, currentPage, totalPages]);

  const handlePrev = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating) return;
    const step = isSpread ? 2 : 1;
    if (currentPage - step >= 0) {
      setDirection('prev');
      setIsAnimating(true);
      setTimeout(() => {
        setCurrentPage(prev => prev - step);
        setIsAnimating(false);
        setDirection(null);
      }, FLIP_DURATION);
    }
  }, [isAnimating, isSpread, currentPage]);

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) return; 
    e.preventDefault();
    const delta = e.deltaY > 0 ? -0.15 : 0.15;
    const newScale = Math.min(Math.max(scale + delta, 1), 3);
    setScale(newScale);
    if (newScale === 1) setPan({ x: 0, y: 0 });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (scale <= 1) return;
    setIsDragging(true);
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || scale <= 1) return;
    const dx = e.clientX - lastMousePos.x;
    const dy = e.clientY - lastMousePos.y;
    setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      readerRef.current?.requestFullscreen();
      setIsFullScreen(true);
    } else {
      document.exitFullscreen();
      setIsFullScreen(false);
    }
  };

  const renderPageImage = (index: number) => {
    if (index < 0 || index >= totalPages) return <div className="w-full h-full bg-[#fdfcf9]" />;
    const url = pages[index].imageUrl;
    return (
      <img 
        src={url} 
        className="w-full h-full object-contain pointer-events-none select-none" 
        style={{ imageRendering: 'auto' }}
        alt="" 
      />
    );
  };

  return (
    <div 
      ref={readerRef} 
      className="flex flex-col h-full bg-[#08090b] text-white overflow-hidden font-inter selection:bg-indigo-500/30 touch-none"
      onWheel={handleWheel}
    >
      {/* Header */}
      <div className="flex items-center justify-between px-6 py-4 bg-black/40 backdrop-blur-2xl border-b border-white/5 z-[60]">
        <div className="flex items-center gap-5">
          <div className="relative">
            <div className="absolute inset-0 bg-indigo-500/20 blur-xl rounded-full" />
            <div className="relative p-2.5 bg-white/5 rounded-xl border border-white/10">
              <BookOpen className="w-5 h-5 text-indigo-300" />
            </div>
          </div>
          <div className="flex flex-col">
            <h2 className="text-sm font-semibold truncate max-w-[150px] md:max-w-md text-slate-100 book-font italic tracking-wide">
              {metadata?.title || 'Untitled Archive'}
            </h2>
            <div className="flex items-center gap-2 mt-0.5">
              <span className="text-[9px] text-slate-500 font-black uppercase tracking-[0.2em]">Authored By</span>
              <span className="text-[10px] text-indigo-400 font-bold uppercase tracking-wider">
                {metadata?.author || 'Unknown'}
              </span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="hidden sm:flex items-center gap-3 px-4 py-2 bg-white/5 rounded-full border border-white/10">
            <Search className="w-3 h-3 text-slate-500" />
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
              Zoom: {Math.round(scale * 100)}%
            </span>
          </div>
          <button 
            onClick={toggleFullScreen}
            className="p-2.5 hover:bg-white/10 rounded-full transition-all active:scale-95 text-slate-400 hover:text-white"
          >
            {isFullScreen ? <Minimize2 className="w-5 h-5" /> : <Maximize2 className="w-5 h-5" />}
          </button>
        </div>
      </div>

      {/* Main 3D Stage */}
      <div 
        className={`flex-1 relative flex items-center justify-center p-8 md:p-14 overflow-hidden perspective-4000 ${scale > 1 ? (isDragging ? 'cursor-grabbing' : 'cursor-grab') : ''}`}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
      >
        <div 
          ref={bookStageRef}
          className="relative transition-transform duration-300 ease-out will-change-transform"
          style={{ 
            transform: `scale(${scale}) translate(${pan.x / scale}px, ${pan.y / scale}px)`,
            transformStyle: 'preserve-3d'
          }}
        >
          <div className={`
            relative flex
            ${isSpread ? 'w-[min(90vw,1200px)] aspect-[1.414/1]' : 'w-[min(88vw,550px)] aspect-[0.707/1]'}
            ${isAnimating ? 'brightness-95' : 'brightness-100'}
          `}
          style={{ transformStyle: 'preserve-3d' }}>

            {/* DESTINATION LAYER (Immediately revealed stationary pages) */}
            <div className="absolute inset-0 flex z-0 rounded-sm overflow-hidden shadow-[0_40px_100px_-20px_rgba(0,0,0,0.8)]" style={{ transform: 'translateZ(-20px)' }}>
               <div className="w-1/2 h-full bg-[#fdfcf9] border-r border-black/5 overflow-hidden">
                 {/* When flipping back, the left underlying page is Target - 1 (P-2) */}
                 {isAnimating && direction === 'prev' ? renderPageImage(currentPage - 2) : renderPageImage(currentPage)}
               </div>
               <div className="w-1/2 h-full bg-[#fdfcf9] overflow-hidden">
                 {/* When flipping next, the right underlying page is Target + 1 (P+3) */}
                 {isAnimating && direction === 'next' ? renderPageImage(currentPage + 3) : renderPageImage(currentPage + 1)}
               </div>
            </div>

            {/* FLIPPING LEAF (Realistic Moving Page) */}
            {isAnimating && isSpread && (
              <div className={`
                absolute top-0 bottom-0 w-1/2 z-[30]
                ${direction === 'next' ? 'right-0 origin-left animate-natural-flip-next' : 'left-0 origin-right animate-natural-flip-prev'}
              `}
              style={{ 
                transformStyle: 'preserve-3d',
                animationDuration: `${FLIP_DURATION}ms`
              }}>

                {/* Front side (Outgoing page - visible during first 50% of turn) */}
                <div className="absolute inset-0 bg-[#fdfcf9] backface-hidden overflow-hidden shadow-2xl">
                  {direction === 'next' ? renderPageImage(currentPage + 1) : renderPageImage(currentPage)}
                  <div className="absolute inset-0 bg-gradient-to-r from-black/20 via-transparent to-black/5" />
                  {/* Dynamic internal shadow that intensifies as page lifts */}
                  <div className="absolute inset-0 bg-black/5 animate-leaf-shadow" />
                </div>

                {/* Back side (Incoming page - revealed during second 50% of turn) */}
                <div className="absolute inset-0 bg-[#fdfcf9] backface-hidden overflow-hidden" 
                     style={{ transform: 'rotateY(180deg)' }}>
                  <div className="w-full h-full scale-x-[-1]">
                    {direction === 'next' ? renderPageImage(currentPage + 2) : renderPageImage(currentPage - 1)}
                  </div>
                  <div className="absolute inset-0 bg-gradient-to-l from-black/20 via-transparent to-black/5" />
                  <div className="absolute inset-0 bg-black/5 animate-leaf-shadow" style={{ animationDelay: `${FLIP_DURATION / 2}ms` }} />
                </div>
              </div>
            )}

            {/* IDLE OVERLAY */}
            {!isAnimating && (
              <div className="absolute inset-0 flex z-10">
                {isSpread ? (
                  <>
                    <div className="w-1/2 h-full bg-[#fdfcf9] border-r border-black/10 overflow-hidden shadow-inner relative">
                      {renderPageImage(currentPage)}
                      <div className="absolute inset-0 bg-gradient-to-r from-black/5 via-transparent to-transparent pointer-events-none" />
                    </div>
                    <div className="w-1/2 h-full bg-[#fdfcf9] overflow-hidden shadow-inner relative">
                      {renderPageImage(currentPage + 1)}
                      <div className="absolute inset-0 bg-gradient-to-l from-black/5 via-transparent to-transparent pointer-events-none" />
                    </div>
                  </>
                ) : (
                  <div className="w-full h-full bg-[#fdfcf9] shadow-2xl">
                    {renderPageImage(currentPage)}
                  </div>
                )}
              </div>
            )}

            {/* DISCREET CORNER TRIGGERS ('Dog-ear' Style) */}
            {!isAnimating && (
              <div className="absolute inset-0 z-[50] pointer-events-none">
                {/* Left Corner (Prev) */}
                {currentPage > 0 && (
                  <div 
                    onClick={handlePrev}
                    className="absolute bottom-0 left-0 w-24 h-24 pointer-events-auto cursor-pointer group flex items-end justify-start overflow-hidden"
                    title="Previous Page"
                  >
                    {/* Small Dog-Ear Triangle */}
                    <div className="absolute bottom-0 left-0 w-0 h-0 border-t-[40px] border-t-transparent border-l-[40px] border-l-slate-200 shadow-sm transition-all duration-500 group-hover:border-l-indigo-400/80 group-hover:border-t-[50px] group-hover:border-l-[50px]" />
                    <div className="relative mb-3 ml-3 p-1.5 opacity-0 group-hover:opacity-100 transition-all duration-300 transform -translate-x-2 group-hover:translate-x-0">
                      <ArrowLeft className="w-4 h-4 text-white drop-shadow-md" />
                    </div>
                  </div>
                )}

                {/* Right Corner (Next) */}
                {currentPage < totalPages - (isSpread ? 2 : 1) && (
                  <div 
                    onClick={handleNext}
                    className="absolute bottom-0 right-0 w-24 h-24 pointer-events-auto cursor-pointer group flex items-end justify-end overflow-hidden"
                    title="Next Page"
                  >
                    {/* Small Dog-Ear Triangle */}
                    <div className="absolute bottom-0 right-0 w-0 h-0 border-t-[40px] border-t-transparent border-r-[40px] border-r-slate-200 shadow-sm transition-all duration-500 group-hover:border-r-indigo-400/80 group-hover:border-t-[50px] group-hover:border-r-[50px]" />
                    <div className="relative mb-3 mr-3 p-1.5 opacity-0 group-hover:opacity-100 transition-all duration-300 transform translate-x-2 group-hover:translate-x-0">
                      <ArrowRight className="w-4 h-4 text-white drop-shadow-md" />
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* Spine with Realistic Depth */}
            {isSpread && (
              <div className="absolute left-1/2 top-0 bottom-0 w-[14px] -translate-x-1/2 z-40
                bg-gradient-to-r from-black/50 via-black/10 to-black/50 shadow-[inset_0_0_10px_rgba(0,0,0,0.4)] opacity-80" />
            )}

            {/* Paper Stack Thickness Visual */}
            <div className="absolute -right-2 top-[0.5%] bottom-[0.5%] w-2 bg-slate-300/30 border-r border-white/5 rounded-r-lg z-0" />
            <div className="absolute -left-2 top-[0.5%] bottom-[0.5%] w-2 bg-slate-300/30 border-l border-white/5 rounded-l-lg z-0" />
          </div>
        </div>

        {/* User Interaction Hint */}
        {scale === 1 && !isAnimating && (
          <div className="absolute bottom-8 left-1/2 -translate-x-1/2 px-4 py-2 bg-white/5 backdrop-blur-md rounded-full border border-white/10 opacity-30 hover:opacity-100 transition-opacity flex items-center gap-3 pointer-events-none">
            <MousePointer2 className="w-3 h-3 text-indigo-400" />
            <span className="text-[9px] font-black uppercase tracking-[0.2em] text-slate-300">Wheel Zoom • Corner Tap</span>
          </div>
        )}
      </div>

      {/* Footer Navigation Bar */}
      <div className="bg-black/90 backdrop-blur-4xl border-t border-white/5 px-8 py-6 z-[60]">
        <div className="max-w-4xl mx-auto">
          <div className="flex items-end justify-between mb-3">
             <div className="flex flex-col">
               <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.4em]">Manuscript Progress</span>
               <span className="text-sm font-bold text-indigo-300 mt-1 flex items-center gap-2">
                 <Sparkles className="w-4 h-4" />
                 {Math.round(((currentPage + (isSpread ? 2 : 1)) / totalPages) * 100)}% Absorbed
               </span>
             </div>
             <div className="flex items-center gap-5">
                <div className="flex items-center gap-2 text-[11px] font-bold text-slate-400 uppercase tracking-[0.2em]">
                  <span>P. {currentPage + 1}</span>
                  <div className="w-1.5 h-1.5 bg-slate-800 rounded-full" />
                  <span>TOTAL {totalPages}</span>
                </div>
                <div className="flex gap-2.5">
                  <button onClick={handlePrev} disabled={currentPage === 0 || isAnimating} className="p-3 bg-white/5 border border-white/10 rounded-xl hover:bg-white/10 active:scale-95 disabled:opacity-20 transition-all"><ChevronLeft className="w-5 h-5" /></button>
                  <button onClick={handleNext} disabled={currentPage >= totalPages - (isSpread ? 2 : 1) || isAnimating} className="p-3 bg-white/5 border border-white/10 rounded-xl hover:bg-white/10 active:scale-95 disabled:opacity-20 transition-all"><ChevronRight className="w-5 h-5" /></button>
                </div>
             </div>
          </div>
          <div className="relative h-1.5 w-full bg-slate-900 rounded-full overflow-hidden shadow-inner">
            <div 
              className="h-full bg-gradient-to-r from-indigo-700 via-indigo-500 to-indigo-600 transition-all duration-1500 cubic-bezier(0.2, 0.8, 0.2, 1) relative"
              style={{ width: `${((currentPage + (isSpread ? 2 : 1)) / totalPages) * 100}%` }}
            >
              <div className="absolute right-0 top-0 bottom-0 w-24 bg-gradient-to-r from-transparent to-white/30 blur-md" />
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .perspective-4000 { perspective: 4000px; }
        .backface-hidden { backface-visibility: hidden; -webkit-backface-visibility: hidden; }
        .backdrop-blur-4xl { backdrop-filter: blur(80px); }

        /* Realistic Flip Keyframes with Inertia and Lift */
        @keyframes natural-flip-next {
          0% { transform: rotateY(0deg) scale(1) translateZ(0); filter: brightness(1); }
          25% { transform: rotateY(-45deg) scale(1.05) translateZ(50px) rotateX(2deg); filter: brightness(1.1); }
          50% { transform: rotateY(-90deg) scale(1.1) translateZ(100px) rotateX(4deg); filter: brightness(1.2); }
          75% { transform: rotateY(-135deg) scale(1.05) translateZ(50px) rotateX(2deg); filter: brightness(1.1); }
          100% { transform: rotateY(-180deg) scale(1) translateZ(0) rotateX(0); filter: brightness(1.05); }
        }

        @keyframes natural-flip-prev {
          0% { transform: rotateY(0deg) scale(1) translateZ(0); filter: brightness(1); }
          25% { transform: rotateY(45deg) scale(1.05) translateZ(50px) rotateX(-2deg); filter: brightness(1.1); }
          50% { transform: rotateY(90deg) scale(1.1) translateZ(100px) rotateX(-4deg); filter: brightness(1.2); }
          75% { transform: rotateY(135deg) scale(1.05) translateZ(50px) rotateX(-2deg); filter: brightness(1.1); }
          100% { transform: rotateY(180deg) scale(1) translateZ(0) rotateX(0); filter: brightness(1.05); }
        }

        @keyframes leaf-shadow {
          0%, 100% { opacity: 0; }
          50% { opacity: 0.3; }
        }

        .animate-natural-flip-next { 
          animation: natural-flip-next 1500ms cubic-bezier(0.45, 0.05, 0.55, 0.95) forwards; 
        }
        .animate-natural-flip-prev { 
          animation: natural-flip-prev 1500ms cubic-bezier(0.45, 0.05, 0.55, 0.95) forwards; 
        }
        .animate-leaf-shadow {
          animation: leaf-shadow 1500ms ease-in-out forwards;
        }
      `}</style>
    </div>
  );
};

