import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ChevronLeft, ChevronRight, Maximize2, Minimize2, BookOpen, Sparkles, Search, MousePointer2, ArrowLeft, ArrowRight } from 'lucide-react';
import { PageData, BookMetadata } from '../types';

interface ReaderProps {
  pages: PageData[];
  metadata: BookMetadata | null;
}

const Reader: React.FC<ReaderProps> = ({ pages, metadata }) => {
  const [currentPage, setCurrentPage] = useState(0);
  const [isSpread, setIsSpread] = useState(window.innerWidth > 1024);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'next' | 'prev' | null>(null);

  // Zoom & Pan State
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [lastMousePos, setLastMousePos] = useState({ x: 0, y: 0 });

  const readerRef = useRef<HTMLDivElement>(null);
  const bookStageRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleResize = () => {
      setIsSpread(window.innerWidth > 1024);
      setScale(1);
      setPan({ x: 0, y: 0 });
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const totalPages = pages.length;
  const FLIP_DURATION = 1400; // Controlled, elegant speed

  const handleNext = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating) return;
    const step = isSpread ? 2 : 1;
    if (currentPage + step < totalPages) {
      setDirection('next');
      setIsAnimating(true);
      setTimeout(() => {
        setCurrentPage(prev => prev + step);
        setIsAnimating(false);
        setDirection(null);
      }, FLIP_DURATION);
    }
  }, [isAnimating, isSpread, currentPage, totalPages]);

  const handlePrev = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating) return;
    const step = isSpread ? 2 : 1;
    if (currentPage - step >= 0) {
      setDirection('prev');
      setIsAnimating(true);
      setTimeout(() => {
        setCurrentPage(prev => prev - step);
        setIsAnimating(false);
        setDirection(null);
      }, FLIP_DURATION);
    }
  }, [isAnimating, isSpread, currentPage]);

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) return; 
    e.preventDefault();
    const delta = e.deltaY > 0 ? -0.15 : 0.15;
    const newScale = Math.min(Math.max(scale + delta, 1), 3);
    setScale(newScale);
    if (newScale === 1) setPan({ x: 0, y: 0 });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (scale <= 1) return;
    setIsDragging(true);
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || scale <= 1) return;
    const dx = e.clientX - lastMousePos.x;
    const dy = e.clientY - lastMousePos.y;
    setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      readerRef.current?.requestFullscreen();
      setIsFullScreen(true);
    } else {
      document.exitFullscreen();
      setIsFullScreen(false);
    }
  };

  const renderPageImage = (index: number) => {
    if (index < 0 || index >= totalPages) return <div className="w-full h-full bg-[#fdfcf9]" />;
    const url = pages[index].imageUrl;
    return (
      <img 
        src={url} 
        className="w-full h-full object-contain pointer-events-none select-none" 
        style={{ imageRendering: 'auto' }}
        alt="" 
      />
    );
  };

  return (
    <div 
      ref={readerRef} 
      className="flex flex-col h-full bg-[#08090b] text-white overflow-hidden font-inter selection:bg-indigo-500/30 touch-none"
      onWheel={handleWheel}
    >
      {/* Header */}
      <div className="flex items-center justify-between px-6 py-4 bg-black/40 backdrop-blur-2xl border-b border-white/5 z-[60]">
        <div className="flex items-center gap-5">
          <div className="relative">
            <div className="absolute inset-0 bg-indigo-500/20 blur-xl rounded-full" />
            <div className="relative p-2.5 bg-white/5 rounded-xl border border-white/10">
              <BookOpen className="w-5 h-5 text-indigo-300" />
            </div>
          </div>
          <div className="flex flex-col">
            <h2 className="text-sm font-semibold truncate max-w-[150px] md:max-w-md text-slate-100 book-font italic tracking-wide">
              {metadata?.title || 'Untitled Archive'}
            </h2>
            <div className="flex items-center gap-2 mt-0.5">
              <span className="text-[9px] text-slate-500 font-black uppercase tracking-[0.2em]">Authored By</span>
              <span className="text-[10px] text-indigo-400 font-bold uppercase tracking-wider">
                {metadata?.author || 'Unknown'}
              </span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="hidden sm:flex items-center gap-3 px-4 py-2 bg-white/5 rounded-full border border-white/10">
            <Search className="w-3 h-3 text-slate-500" />
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
              Zoom: {Math.round(scale * 100)}%
            </span>
          </div>
          <button 
            onClick={toggleFullScreen}
            className="p-2.5 hover:bg-white/10 rounded-full transition-all active:scale-95 text-slate-400 hover:text-white"
          >
            {isFullScreen ? <Minimize2 className="w-5 h-5" /> : <Maximize2 className="w-5 h-5" />}
          </button>
        </div>
      </div>

      {/* Main 3D Stage */}
      <div 
        className={`flex-1 relative flex items-center justify-center p-8 md:p-14 overflow-hidden perspective-4000 ${scale > 1 ? (isDragging ? 'cursor-grabbing' : 'cursor-grab') : ''}`}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
      >
        <div 
          ref={bookStageRef}
          className="relative transition-transform duration-300 ease-out will-change-transform"
          style={{ 
            transform: `scale(${scale}) translate(${pan.x / scale}px, ${pan.y / scale}px)`,
            transformStyle: 'preserve-3d'
          }}
        >
          <div className={`
            relative flex
            ${isSpread ? 'w-[min(90vw,1200px)] aspect-[1.414/1]' : 'w-[min(88vw,550px)] aspect-[0.707/1]'}
            ${isAnimating ? 'brightness-95' : 'brightness-100'}
          `}
          style={{ transformStyle: 'preserve-3d' }}>

            {/* UNDERLYING STATIONARY LAYER */}
            <div className="absolute inset-0 flex z-0 rounded-sm overflow-hidden" style={{ transform: 'translateZ(-1px)' }}>
               {/* Left Side Static */}
               <div className="w-1/2 h-full bg-[#fdfcf9] border-r border-black/5 overflow-hidden">
                 {isAnimating && direction === 'prev' ? renderPageImage(currentPage - 2) : renderPageImage(currentPage)}
                 <div className="absolute inset-0 bg-gradient-to-r from-black/5 via-transparent to-transparent pointer-events-none" />
               </div>
               {/* Right Side Static */}
               <div className="w-1/2 h-full bg-[#fdfcf9] overflow-hidden">
                 {isAnimating && direction === 'next' ? renderPageImage(currentPage + 3) : renderPageImage(currentPage + 1)}
                 <div className="absolute inset-0 bg-gradient-to-l from-black/5 via-transparent to-transparent pointer-events-none" />
               </div>
            </div>

            {/* THE FLIPPING LEAF (The Moving Page) */}
            {isAnimating && isSpread && (
              <div className={`
                absolute top-0 bottom-0 w-1/2 z-[30]
                ${direction === 'next' ? 'right-0 origin-left animate-natural-flip-next' : 'left-0 origin-right animate-natural-flip-prev'}
              `}
              style={{ 
                transformStyle: 'preserve-3d',
                animationDuration: `${FLIP_DURATION}ms`
              }}>

                {/* Outgoing Side of the Flip (Front) */}
                <div className="absolute inset-0 bg-[#fdfcf9] backface-hidden overflow-hidden shadow-2xl">
                  {direction === 'next' ? renderPageImage(currentPage + 1) : renderPageImage(currentPage)}
                  {/* Spine-side shading */}
                  <div className={`absolute inset-0 ${direction === 'next' ? 'bg-gradient-to-r' : 'bg-gradient-to-l'} from-black/20 via-transparent to-transparent`} />
                  {/* Dynamic surface highlight shadow */}
                  <div className="absolute inset-0 animate-leaf-surface-shading" />
                </div>

                {/* Incoming Side of the Flip (Back) */}
                <div className="absolute inset-0 bg-[#fdfcf9] backface-hidden overflow-hidden" 
                     style={{ transform: 'rotateY(180deg)' }}>
                  <div className="w-full h-full scale-x-[-1]">
                    {direction === 'next' ? renderPageImage(currentPage + 2) : renderPageImage(currentPage - 1)}
                  </div>
                  {/* Reverse shading for the back side */}
                  <div className={`absolute inset-0 ${direction === 'next' ? 'bg-gradient-to-l' : 'bg-gradient-to-r'} from-black/20 via-transparent to-transparent`} />
                  <div className="absolute inset-0 animate-leaf-surface-shading" style={{ animationDelay: `${FLIP_DURATION / 2}ms` }} />
                </div>
              </div>
            )}

            {/* IDLE OVERLAY (Only visible when not moving) */}
            {!isAnimating && (
              <div className="absolute inset-0 flex z-10">
                {isSpread ? (
                  <>
                    <div className="w-1/2 h-full bg-[#fdfcf9] border-r border-black/10 overflow-hidden shadow-inner relative">
                      {renderPageImage(currentPage)}
                      <div className="absolute inset-0 bg-gradient-to-r from-black/10 via-transparent to-transparent pointer-events-none" />
                    </div>
                    <div className="w-1/2 h-full bg-[#fdfcf9] overflow-hidden shadow-inner relative">
                      {renderPageImage(currentPage + 1)}
                      <div className="absolute inset-0 bg-gradient-to-l from-black/10 via-transparent to-transparent pointer-events-none" />
                    </div>
                  </>
                ) : (
                  <div className="w-full h-full bg-[#fdfcf9] shadow-2xl">
                    {renderPageImage(currentPage)}
                  </div>
                )}
              </div>
            )}

            {/* DISCREET DOG-EAR TRIGGERS */}
            {!isAnimating && (
              <div className="absolute inset-0 z-[50] pointer-events-none">
                {/* Previous (Bottom Left) */}
                {currentPage > 0 && (
                  <div 
                    onClick={handlePrev}
                    className="absolute bottom-0 left-0 w-28 h-28 pointer-events-auto cursor-pointer group"
                    title="Previous Page"
                  >
                    <div className="absolute bottom-0 left-0 w-0 h-0 border-t-[45px] border-t-transparent border-l-[45px] border-l-slate-200/80 shadow-sm transition-all duration-500 group-hover:border-l-indigo-500/60 group-hover:border-t-[55px] group-hover:border-l-[55px]" />
                    <div className="absolute bottom-4 left-4 p-1.5 opacity-0 group-hover:opacity-100 transition-all duration-300">
                      <ArrowLeft className="w-4 h-4 text-white drop-shadow-md" />
                    </div>
                  </div>
                )}

                {/* Next (Bottom Right) */}
                {currentPage < totalPages - (isSpread ? 2 : 1) && (
                  <div 
                    onClick={handleNext}
                    className="absolute bottom-0 right-0 w-28 h-28 pointer-events-auto cursor-pointer group"
                    title="Next Page"
                  >
                    <div className="absolute bottom-0 right-0 w-0 h-0 border-t-[45px] border-t-transparent border-r-[45px] border-r-slate-200/80 shadow-sm transition-all duration-500 group-hover:border-r-indigo-500/60 group-hover:border-t-[55px] group-hover:border-r-[55px]" />
                    <div className="absolute bottom-4 right-4 p-1.5 opacity-0 group-hover:opacity-100 transition-all duration-300">
                      <ArrowRight className="w-4 h-4 text-white drop-shadow-md" />
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* Spine depth visual */}
            {isSpread && (
              <div className="absolute left-1/2 top-0 bottom-0 w-[16px] -translate-x-1/2 z-40
                bg-gradient-to-r from-black/60 via-black/5 to-black/60 opacity-80" />
            )}

            {/* Edge stack visual */}
            <div className="absolute -right-2 top-[0.5%] bottom-[0.5%] w-2 bg-slate-400/20 border-r border-white/5 rounded-r-lg z-0" />
            <div className="absolute -left-2 top-[0.5%] bottom-[0.5%] w-2 bg-slate-400/20 border-l border-white/5 rounded-l-lg z-0" />
          </div>
        </div>
      </div>

      {/* Footer Progress & Nav */}
      <div className="bg-black/90 backdrop-blur-4xl border-t border-white/5 px-8 py-6 z-[60]">
        <div className="max-w-4xl mx-auto">
          <div className="flex items-end justify-between mb-3">
             <div className="flex flex-col">
               <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.4em]">Manuscript Progress</span>
               <span className="text-sm font-bold text-indigo-300 mt-1 flex items-center gap-2">
                 <Sparkles className="w-4 h-4" />
                 {Math.round(((currentPage + (isSpread ? 2 : 1)) / totalPages) * 100)}% Absorbed
               </span>
             </div>
             <div className="flex items-center gap-5">
                <div className="flex items-center gap-2 text-[11px] font-bold text-slate-400 uppercase tracking-[0.2em]">
                  <span>P. {currentPage + 1}</span>
                  <div className="w-1.5 h-1.5 bg-slate-800 rounded-full" />
                  <span>TOTAL {totalPages}</span>
                </div>
                <div className="flex gap-2.5">
                  <button onClick={handlePrev} disabled={currentPage === 0 || isAnimating} className="p-3 bg-white/5 border border-white/10 rounded-xl hover:bg-white/10 active:scale-95 disabled:opacity-20 transition-all"><ChevronLeft className="w-5 h-5" /></button>
                  <button onClick={handleNext} disabled={currentPage >= totalPages - (isSpread ? 2 : 1) || isAnimating} className="p-3 bg-white/5 border border-white/10 rounded-xl hover:bg-white/10 active:scale-95 disabled:opacity-20 transition-all"><ChevronRight className="w-5 h-5" /></button>
                </div>
             </div>
          </div>
          <div className="relative h-1.5 w-full bg-slate-900 rounded-full overflow-hidden shadow-inner">
            <div 
              className="h-full bg-gradient-to-r from-indigo-700 via-indigo-500 to-indigo-600 transition-all duration-1500 cubic-bezier(0.2, 0.8, 0.2, 1) relative"
              style={{ width: `${((currentPage + (isSpread ? 2 : 1)) / totalPages) * 100}%` }}
            >
              <div className="absolute right-0 top-0 bottom-0 w-24 bg-gradient-to-r from-transparent to-white/30 blur-md" />
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .perspective-4000 { perspective: 4000px; }
        .backface-hidden { backface-visibility: hidden; -webkit-backface-visibility: hidden; }
        .backdrop-blur-4xl { backdrop-filter: blur(80px); }

        /* THE SEAMLESS FLIP: Refined to pivot exactly around the spine without gaps */
        @keyframes natural-flip-next {
          0% { transform: rotateY(0deg) translateZ(0); filter: brightness(1); }
          50% { transform: rotateY(-90deg) translateZ(60px) scale(1.08); filter: brightness(1.15); }
          100% { transform: rotateY(-180deg) translateZ(0); filter: brightness(1); }
        }

        @keyframes natural-flip-prev {
          0% { transform: rotateY(0deg) translateZ(0); filter: brightness(1); }
          50% { transform: rotateY(90deg) translateZ(60px) scale(1.08); filter: brightness(1.15); }
          100% { transform: rotateY(180deg) translateZ(0); filter: brightness(1); }
        }

        @keyframes leaf-surface-shading {
          0%, 100% { background-color: rgba(0,0,0,0); }
          50% { background-color: rgba(0,0,0,0.15); }
        }

        .animate-natural-flip-next { 
          animation: natural-flip-next 1400ms cubic-bezier(0.42, 0, 0.58, 1) forwards; 
        }
        .animate-natural-flip-prev { 
          animation: natural-flip-prev 1400ms cubic-bezier(0.42, 0, 0.58, 1) forwards; 
        }
        .animate-leaf-surface-shading {
          animation: leaf-surface-shading 1400ms ease-in-out forwards;
        }
      `}</style>
    </div>
  );
};

