        @keyframes page-flip-next {
          0% { transform: rotateY(0deg) translateZ(1px); }
          100% { transform: rotateY(-180deg) translateZ(1px); }
        }

        @keyframes page-flip-prev {
          0% { transform: rotateY(0deg) translateZ(1px); }
          100% { transform: rotateY(180deg) translateZ(1px); }
        }

        /* Lighting effects during flip */
        @keyframes flip-shadow-front {
          0% { background: rgba(0,0,0,0); }
          50% { background: rgba(0,0,0,0.3); }
          100% { background: rgba(0,0,0,0); }
        }

        @keyframes flip-shadow-back {
          0% { background: rgba(0,0,0,0.4); }
          50% { background: rgba(0,0,0,0.1); }
          100% { background: rgba(0,0,0,0); }
        }

        .animate-page-flip-next { 
          animation-name: page-flip-next;
          animation-fill-mode: forwards;
        }
        .animate-page-flip-prev { 
          animation-name: page-flip-prev;
          animation-fill-mode: forwards;
        }
        .animate-flip-shadow-front { animation-fill-mode: forwards; animation-name: flip-shadow-front; }
        .animate-flip-shadow-back { animation-fill-mode: forwards; animation-name: flip-shadow-back; }

        .backface-hidden {
          backface-visibility: hidden;
          -webkit-backface-visibility: hidden;
        }
      `}</style>
    </div>
  );
};

