          100% { transform: rotateY(-180deg) translateZ(0); }
        }

        @keyframes leaf-flip-prev {
          0% { transform: rotateY(0deg) translateZ(0); }
          50% { transform: rotateY(90deg) translateZ(80px) scale(1.05); }
          100% { transform: rotateY(180deg) translateZ(0); }
        }

        /* 플립 중 발생하는 다이내믹 섀도우 (입체감 부여) */
        @keyframes flip-shading {
          0%, 100% { background-color: rgba(0,0,0,0); }
          50% { background-color: rgba(0,0,0,0.15); }
        }

        @keyframes flip-shading-reverse {
          0%, 100% { background-color: rgba(0,0,0,0); }
          50% { background-color: rgba(0,0,0,0.1); }
        }

        .animate-leaf-next { animation-name: leaf-flip-next; animation-fill-mode: forwards; }
        .animate-leaf-prev { animation-name: leaf-flip-prev; animation-fill-mode: forwards; }
        .animate-flip-shading { animation-fill-mode: forwards; animation-name: flip-shading; }
        .animate-flip-shading-reverse { animation-fill-mode: forwards; animation-name: flip-shading-reverse; }

        .backface-hidden {
          backface-visibility: hidden;
          -webkit-backface-visibility: hidden;
        }
      `}</style>
    </div>
  );
};

export default Reader;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ChevronLeft, ChevronRight, Maximize2, Minimize2, BookOpen, Sparkles, ArrowLeft, ArrowRight } from 'lucide-react';
import { PageData, BookMetadata } from '../types';

interface ReaderProps {
  pages: PageData[];
  metadata: BookMetadata | null;
}

const Reader: React.FC<ReaderProps> = ({ pages, metadata }) => {
  const [currentPage, setCurrentPage] = useState(0);
  const [isSpread, setIsSpread] = useState(window.innerWidth > 1024);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'next' | 'prev' | null>(null);

  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });

  const readerRef = useRef<HTMLDivElement>(null);
  const FLIP_DURATION = 1400; // 물리적으로 가장 적당한 속도

  useEffect(() => {
    const handleResize = () => {
      setIsSpread(window.innerWidth > 1024);
      setScale(1);
      setPan({ x: 0, y: 0 });
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const totalPages = pages.length;

  const handleNext = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating || currentPage >= totalPages - (isSpread ? 2 : 1)) return;

    setDirection('next');
    setIsAnimating(true);

    setTimeout(() => {
      setCurrentPage(prev => prev + (isSpread ? 2 : 1));
      setIsAnimating(false);
      setDirection(null);
    }, FLIP_DURATION);
  }, [isAnimating, isSpread, currentPage, totalPages]);

  const handlePrev = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating || currentPage <= 0) return;

    setDirection('prev');
    setIsAnimating(true);

    setTimeout(() => {
      setCurrentPage(prev => prev - (isSpread ? 2 : 1));
      setIsAnimating(false);
      setDirection(null);
    }, FLIP_DURATION);
  }, [isAnimating, isSpread, currentPage]);

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) return; 
    e.preventDefault();
    const delta = e.deltaY > 0 ? -0.15 : 0.15;
    const newScale = Math.min(Math.max(scale + delta, 1), 3);
    setScale(newScale);
  };

  const renderPageImage = (index: number, extraClasses: string = "", isReversed: boolean = false) => {
    if (index < 0 || index >= totalPages) return <div className={`w-full h-full bg-[#fdfcf9] ${extraClasses}`} />;
    return (
      <div className={`w-full h-full bg-[#fdfcf9] relative overflow-hidden ${extraClasses}`}>
        <img 
          src={pages[index].imageUrl} 
          className={`w-full h-full object-contain pointer-events-none select-none ${isReversed ? 'scale-x-[-1]' : ''}`}
          style={{ imageRendering: 'auto' }}
          alt={`Page ${index + 1}`} 
        />
        {/* 미세한 종이 질감 */}
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/paper-fibers.png')] opacity-[0.05] pointer-events-none" />
      </div>
    );
  };

  return (
    <div 
      ref={readerRef} 
      className="flex flex-col h-full bg-[#0a0b0e] text-white overflow-hidden font-inter selection:bg-indigo-500/30 touch-none"
      onWheel={handleWheel}
    >
      {/* 상단 바 */}
      <div className="flex items-center justify-between px-6 py-4 bg-black/60 backdrop-blur-2xl border-b border-white/5 z-[100]">
        <div className="flex items-center gap-4">
          <BookOpen className="w-5 h-5 text-indigo-400" />
          <h2 className="text-sm font-semibold text-slate-100 italic tracking-wide truncate max-w-[250px]">
            {metadata?.title || 'Loading Document...'}
          </h2>
        </div>
        <div className="flex items-center gap-4">
          <div className="bg-white/5 px-3 py-1 rounded-full border border-white/10 text-[10px] font-bold text-slate-400">
            {Math.round(scale * 100)}%
          </div>
          <button onClick={() => isFullScreen ? document.exitFullscreen() : readerRef.current?.requestFullscreen()} className="p-2 hover:bg-white/10 rounded-full transition-colors">
            {isFullScreen ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
          </button>
        </div>
      </div>

      {/* 3D 스테이지 */}
      <div 
        className="flex-1 relative flex items-center justify-center p-8 md:p-20 overflow-hidden"
        style={{ perspective: '3500px' }}
      >
        <div 
          className="relative transition-transform duration-300 ease-out"
          style={{ 
            transform: `scale(${scale}) translate(${pan.x}px, ${pan.y}px)`,
            transformStyle: 'preserve-3d'
          }}
        >
          {/* 책 메인 컨테이너 */}
          <div 
            className={`relative flex shadow-[0_50px_100px_-20px_rgba(0,0,0,0.9)] ${isSpread ? 'w-[min(92vw,1150px)]' : 'w-[min(88vw,480px)]'} aspect-[1.414/1] bg-[#fdfcf9] rounded-sm`} 
            style={{ transformStyle: 'preserve-3d' }}
          >

            {/* 1. BASE LAYER (바닥에 항상 깔려있는 페이지) */}
            <div className="absolute inset-0 flex z-0" style={{ transformStyle: 'preserve-3d', transform: 'translateZ(-4px)' }}>
               {/* 왼쪽 바닥 */}
               <div className="w-1/2 h-full border-r border-black/5 relative">
                 {isAnimating && direction === 'prev' 
                    ? renderPageImage(currentPage - 2) // 뒤로 넘길 때 바닥에 보일 이전 왼쪽 페이지
                    : renderPageImage(currentPage)      // 평소 혹은 앞으로 넘길 때 보일 왼쪽 페이지
                 }
                 <div className="absolute inset-0 bg-gradient-to-r from-black/5 via-transparent to-transparent pointer-events-none" />
               </div>
               {/* 오른쪽 바닥 */}
               <div className="w-1/2 h-full relative">
                 {isAnimating && direction === 'next' 
                    ? renderPageImage(currentPage + 3) // 앞으로 넘길 때 바닥에 보일 미래의 오른쪽 페이지
                    : renderPageImage(currentPage + 1) // 평소 혹은 뒤로 넘길 때 보일 오른쪽 페이지
                 }
                 <div className="absolute inset-0 bg-gradient-to-l from-black/5 via-transparent to-transparent pointer-events-none" />
               </div>
            </div>

            {/* 2. FLIPPING LEAF (실제로 공중에서 회전하는 종이) */}
            {isAnimating && (
              <div className={`
                absolute top-0 bottom-0 w-1/2 z-[50]
                ${direction === 'next' ? 'right-0 origin-left animate-page-next' : 'left-0 origin-right animate-page-prev'}
              `}
              style={{ 
                transformStyle: 'preserve-3d',
                animationDuration: `${FLIP_DURATION}ms`,
                animationTimingFunction: 'cubic-bezier(0.42, 0, 0.58, 1)' 
              }}>
                {/* 회전하는 종이의 앞면 (현재 페이지) */}
                <div className="absolute inset-0 backface-hidden z-20 shadow-2xl">
                  {direction === 'next' ? renderPageImage(currentPage + 1) : renderPageImage(currentPage)}
                  <div className="absolute inset-0 animate-flip-shadow-front" style={{ animationDuration: `${FLIP_DURATION}ms` }} />
                </div>

                {/* 회전하는 종이의 뒷면 (넘어온 후 보일 페이지) */}
                <div className="absolute inset-0 backface-hidden z-10" style={{ transform: 'rotateY(180deg)' }}>
                  {/* scale-x-[-1]을 통해 rotateY(180)로 인한 반전을 다시 원상복구함 */}
                  {direction === 'next' ? renderPageImage(currentPage + 2, "", true) : renderPageImage(currentPage - 1, "", true)}
                  <div className="absolute inset-0 animate-flip-shadow-back" style={{ animationDuration: `${FLIP_DURATION}ms` }} />
                </div>
              </div>
            )}

            {/* 3. STATIC OVERLAY (애니메이션이 아닐 때만 덮어씌움 - 렌더링 최적화) */}
            {!isAnimating && (
              <div className="absolute inset-0 flex z-40" style={{ transformStyle: 'preserve-3d' }}>
                <div className="w-1/2 h-full border-r border-black/10 relative">
                  {renderPageImage(currentPage)}
                  <div className="absolute inset-0 bg-gradient-to-r from-black/10 via-transparent to-transparent pointer-events-none" />
                </div>
                <div className="w-1/2 h-full relative">
                  {renderPageImage(currentPage + 1)}
                  <div className="absolute inset-0 bg-gradient-to-l from-black/10 via-transparent to-transparent pointer-events-none" />
                </div>
              </div>
            )}

            {/* 책의 중심선 (Spine) */}
            <div className="absolute left-1/2 top-0 bottom-0 w-[12px] -translate-x-1/2 z-[100] 
              bg-gradient-to-r from-black/50 via-black/5 to-black/50 opacity-60 border-x border-white/5" />

            {/* 구석 넘기기 트리거 (Dog-ears) */}
            {!isAnimating && (
              <div className="absolute inset-0 z-[110] pointer-events-none">
                {currentPage > 0 && (
                  <div onClick={handlePrev} className="absolute bottom-0 left-0 w-32 h-32 pointer-events-auto cursor-pointer group">
                    <div className="absolute bottom-0 left-0 w-0 h-0 border-t-[35px] border-t-transparent border-l-[35px] border-l-slate-400/20 group-hover:border-l-indigo-500/50 group-hover:border-t-[45px] group-hover:border-l-[45px] transition-all duration-500" />
                    <ArrowLeft className="absolute bottom-3 left-3 w-4 h-4 text-white opacity-0 group-hover:opacity-100 transition-opacity" />
                  </div>
                )}
                {currentPage < totalPages - (isSpread ? 2 : 1) && (
                  <div onClick={handleNext} className="absolute bottom-0 right-0 w-32 h-32 pointer-events-auto cursor-pointer group">
                    <div className="absolute bottom-0 right-0 w-0 h-0 border-t-[35px] border-t-transparent border-r-[35px] border-r-slate-400/20 group-hover:border-r-indigo-500/50 group-hover:border-t-[45px] group-hover:border-r-[45px] transition-all duration-500" />
                    <ArrowRight className="absolute bottom-3 right-3 w-4 h-4 text-white opacity-0 group-hover:opacity-100 transition-opacity" />
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* 하단 내비게이션 */}
      <div className="bg-black/80 backdrop-blur-2xl border-t border-white/5 p-6 z-[100]">
        <div className="max-w-4xl mx-auto flex items-center justify-between gap-10">
          <div className="flex flex-col min-w-[120px]">
            <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Archive Flow</span>
            <div className="flex items-center gap-2 mt-1">
              <Sparkles className="w-3 h-3 text-indigo-400" />
              <span className="text-xs font-bold text-slate-200">PAGE {currentPage + 1}-{Math.min(currentPage + (isSpread ? 2 : 1), totalPages)} / {totalPages}</span>
            </div>
          </div>

          <div className="flex-1 relative h-1 bg-white/5 rounded-full overflow-hidden shadow-inner">
            <div 
              className="absolute left-0 top-0 h-full bg-gradient-to-r from-indigo-700 to-indigo-400 transition-all duration-700"
              style={{ width: `${((currentPage + (isSpread ? 2 : 1)) / totalPages) * 100}%` }}
            />
          </div>

          <div className="flex gap-2">
            <button onClick={handlePrev} disabled={isAnimating || currentPage === 0} className="p-3 bg-white/5 rounded-xl hover:bg-white/10 disabled:opacity-10 transition-all active:scale-90 border border-white/5">
              <ChevronLeft className="w-5 h-5 text-slate-400" />
            </button>
            <button onClick={handleNext} disabled={isAnimating || currentPage >= totalPages - (isSpread ? 2 : 1)} className="p-3 bg-white/5 rounded-xl hover:bg-white/10 disabled:opacity-10 transition-all active:scale-90 border border-white/5">
              <ChevronRight className="w-5 h-5 text-slate-400" />
            </button>
          </div>
        </div>
      </div>

      <style>{`
        /* 90도 지점에서 내용이 바뀌고 입체감을 주는 물리 애니메이션 */
        @keyframes page-flip-next {
          0% { transform: rotateY(0deg) translateZ(0); }
          50% { transform: rotateY(-90deg) translateZ(100px) scale(1.04); }
          100% { transform: rotateY(-180deg) translateZ(0); }
        }

        @keyframes page-flip-prev {
          0% { transform: rotateY(0deg) translateZ(0); }
          50% { transform: rotateY(90deg) translateZ(100px) scale(1.04); }
          100% { transform: rotateY(180deg) translateZ(0); }
        }

        /* 90도(수직) 시점에서 그림자가 가장 깊어지는 다이내믹 라이팅 */
        @keyframes shadow-dynamics-front {
          0% { background-color: rgba(0,0,0,0); }
          50% { background-color: rgba(0,0,0,0.35); }
          100% { background-color: rgba(0,0,0,0); }
        }

        @keyframes shadow-dynamics-back {
          0% { background-color: rgba(0,0,0,0.4); }
          50% { background-color: rgba(0,0,0,0.1); }
          100% { background-color: rgba(0,0,0,0); }
        }

        .animate-page-next { animation-name: page-flip-next; animation-fill-mode: forwards; }
        .animate-page-prev { animation-name: page-flip-prev; animation-fill-mode: forwards; }
        .animate-flip-shadow-front { animation-name: shadow-dynamics-front; animation-fill-mode: forwards; }
        .animate-flip-shadow-back { animation-name: shadow-dynamics-back; animation-fill-mode: forwards; }

        .backface-hidden {
          backface-visibility: hidden;
          -webkit-backface-visibility: hidden;
        }
      `}</style>
    </div>
  );
};

export default Reader;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ChevronLeft, ChevronRight, Maximize2, Minimize2, BookOpen, Sparkles, ArrowLeft, ArrowRight } from 'lucide-react';
import { PageData, BookMetadata } from '../types';

interface ReaderProps {
  pages: PageData[];
  metadata: BookMetadata | null;
}

const Reader: React.FC<ReaderProps> = ({ pages, metadata }) => {
  const [currentPage, setCurrentPage] = useState(0);
  const [isSpread, setIsSpread] = useState(window.innerWidth > 1024);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'next' | 'prev' | null>(null);
  const [scale, setScale] = useState(1);

  const readerRef = useRef<HTMLDivElement>(null);
  const FLIP_DURATION = 1000; // 가장 자연스러운 물리 속도

  useEffect(() => {
    const handleResize = () => setIsSpread(window.innerWidth > 1024);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const totalPages = pages.length;

  const handleNext = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating || currentPage >= totalPages - (isSpread ? 2 : 1)) return;
    setDirection('next');
    setIsAnimating(true);
    setTimeout(() => {
      setCurrentPage(prev => prev + (isSpread ? 2 : 1));
      setIsAnimating(false);
      setDirection(null);
    }, FLIP_DURATION);
  }, [isAnimating, isSpread, currentPage, totalPages]);

  const handlePrev = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating || currentPage <= 0) return;
    setDirection('prev');
    setIsAnimating(true);
    setTimeout(() => {
      setCurrentPage(prev => prev - (isSpread ? 2 : 1));
      setIsAnimating(false);
      setDirection(null);
    }, FLIP_DURATION);
  }, [isAnimating, isSpread, currentPage]);

  const renderPage = (index: number, extraClasses: string = "", isFlippedSide: boolean = false) => {
    if (index < 0 || index >= totalPages) {
      return <div className={`w-full h-full bg-[#fdfcf9] border border-black/5 ${extraClasses}`} />;
    }
    return (
      <div className={`w-full h-full bg-[#fdfcf9] relative overflow-hidden shadow-inner border border-black/5 ${extraClasses}`}>
        <img 
          src={pages[index].imageUrl} 
          className={`w-full h-full object-contain select-none ${isFlippedSide ? 'scale-x-[-1]' : ''}`}
          style={{ imageRendering: 'high-quality' }}
          alt={`Page ${index + 1}`} 
        />
        {/* Subtle paper grain */}
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/paper-fibers.png')] opacity-[0.04] pointer-events-none" />
      </div>
    );
  };

  return (
    <div ref={readerRef} className="flex flex-col h-full bg-[#08090b] text-white overflow-hidden select-none touch-none">
      {/* Premium Header */}
      <div className="flex items-center justify-between px-8 py-5 bg-black/40 backdrop-blur-xl border-b border-white/5 z-[100]">
        <div className="flex items-center gap-5">
          <div className="p-2 bg-indigo-500/10 rounded-lg">
            <BookOpen className="w-5 h-5 text-indigo-400" />
          </div>
          <div className="flex flex-col">
            <h2 className="text-sm font-bold text-slate-100 book-font italic tracking-wide truncate max-w-[300px]">
              {metadata?.title || 'Universal Manuscript'}
            </h2>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-[0.2em]">{metadata?.author || 'Unknown Author'}</p>
          </div>
        </div>
        <div className="flex items-center gap-6">
          <div className="flex items-center bg-white/5 rounded-full px-4 py-1 border border-white/10 gap-3">
            <span className="text-[10px] font-black text-slate-400">FIDELITY</span>
            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
          </div>
          <button 
            onClick={() => isFullScreen ? document.exitFullscreen() : readerRef.current?.requestFullscreen()} 
            className="p-2.5 hover:bg-white/10 rounded-xl transition-all border border-white/5"
          >
            {isFullScreen ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
          </button>
        </div>
      </div>

      {/* 3D Realistic Environment */}
      <div className="flex-1 relative flex items-center justify-center p-4 md:p-12 overflow-hidden" style={{ perspective: '3000px' }}>
        <div 
          className="relative transition-transform duration-500 ease-out"
          style={{ transform: `scale(${scale})`, transformStyle: 'preserve-3d' }}
        >
          {/* THE BOOK CORE */}
          <div 
            className={`relative flex ${isSpread ? 'w-[min(94vw,1200px)]' : 'w-[min(88vw,500px)]'} aspect-[1.414/1] bg-[#fdfcf9] rounded-[2px] shadow-[0_50px_100px_-20px_rgba(0,0,0,0.8)]`} 
            style={{ transformStyle: 'preserve-3d' }}
          >

            {/* 1. BOTTOM BASE LAYER (넘어가는 동안 밑에 깔려있는 페이지들 - 항상 보임) */}
            <div className="absolute inset-0 flex z-0" style={{ transformStyle: 'preserve-3d', transform: 'translateZ(-10px)' }}>
               <div className="w-1/2 h-full relative">
                 {/* 넘길 때 왼쪽 바닥: 뒤로 넘기기 중이면 '전전' 페이지, 아니면 '현재' 페이지 */}
                 {isAnimating && direction === 'prev' ? renderPage(currentPage - 2) : renderPage(currentPage)}
                 <div className="absolute inset-0 bg-gradient-to-r from-black/20 via-transparent to-transparent opacity-40 pointer-events-none" />
               </div>
               <div className="w-1/2 h-full relative">
                 {/* 넘길 때 오른쪽 바닥: 앞으로 넘기기 중이면 '다음다음' 페이지, 아니면 '다음' 페이지 */}
                 {isAnimating && direction === 'next' ? renderPage(currentPage + 3) : renderPage(currentPage + 1)}
                 <div className="absolute inset-0 bg-gradient-to-l from-black/20 via-transparent to-transparent opacity-40 pointer-events-none" />
               </div>
            </div>

            {/* 2. THE FLIPPING LEAF (실제 공중 회전 오브젝트) */}
            {isAnimating && (
              <div 
                className={`absolute top-0 bottom-0 w-1/2 z-[50] ${direction === 'next' ? 'right-0 origin-left animate-flip-forward' : 'left-0 origin-right animate-flip-backward'}`}
                style={{ 
                  transformStyle: 'preserve-3d', 
                  animationDuration: `${FLIP_DURATION}ms`,
                  animationTimingFunction: 'cubic-bezier(0.645, 0.045, 0.355, 1)' 
                }}
              >
                {/* Front Side: Currently visible page about to flip */}
                <div className="absolute inset-0 backface-hidden z-20">
                  {direction === 'next' ? renderPage(currentPage + 1) : renderPage(currentPage)}
                  <div className="absolute inset-0 animate-light-sweep" style={{ animationDuration: `${FLIP_DURATION}ms` }} />
                </div>

                {/* Back Side: The target page landing from the flip */}
                <div className="absolute inset-0 backface-hidden z-10" style={{ transform: 'rotateY(180deg)' }}>
                  {/* rotateY(180)로 인한 반전을 상쇄하기 위해 내부 이미지만 scaleX(-1) */}
                  <div className="w-full h-full scale-x-[-1]">
                    {direction === 'next' ? renderPage(currentPage + 2) : renderPage(currentPage - 1)}
                  </div>
                  <div className="absolute inset-0 animate-shadow-sweep" style={{ animationDuration: `${FLIP_DURATION}ms` }} />
                </div>
              </div>
            )}

            {/* 3. STATIC OVERLAY (애니메이션 완료 시 정적 상태 유지) */}
            {!isAnimating && (
              <div className="absolute inset-0 flex z-40" style={{ transformStyle: 'preserve-3d' }}>
