import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ChevronLeft, ChevronRight, Maximize2, Minimize2, BookOpen, Sparkles, ArrowLeft, ArrowRight, Volume2, VolumeX } from 'lucide-react';
import { PageData, BookMetadata } from '../types';

interface ReaderProps {
  pages: PageData[];
  metadata: BookMetadata | null;
}

// 프로시저럴 오디오 엔진: 실제 종이 소리 합성
const playPaperFlipSound = () => {
  try {
    const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
    if (!AudioContext) return;

    const ctx = new AudioContext();
    const t = ctx.currentTime;

    // 1. 화이트 노이즈 버퍼 생성 (종이 질감)
    const bufferSize = ctx.sampleRate * 0.8; // 0.8초 길이
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      // 핑크 노이즈 근사치
      const white = Math.random() * 2 - 1;
      data[i] = (lastOut + (0.02 * white)) / 1.02;
      lastOut = data[i];
      data[i] *= 3.5; // Gain 보정
    }

    const noiseSrc = ctx.createBufferSource();
    noiseSrc.buffer = buffer;

    // 2. 필터링 (종이의 먹먹한 소리)
    const filter = ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.setValueAtTime(800, t);
    filter.frequency.linearRampToValueAtTime(1200, t + 0.2); // 주파수 이동으로 '휙' 소리 구현

    // 3. 엔벨로프 (소리의 모양)
    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(0.15, t + 0.05); // Attack
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.4); // Release

    noiseSrc.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);

    noiseSrc.start(t);
    noiseSrc.stop(t + 0.5);
  } catch (e) {
    console.error("Audio play failed", e);
  }
};
let lastOut = 0;

const Reader: React.FC<ReaderProps> = ({ pages, metadata }) => {
  const [currentPage, setCurrentPage] = useState(0);
  const [isSpread, setIsSpread] = useState(window.innerWidth > 1024);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'next' | 'prev' | null>(null);
  const [soundEnabled, setSoundEnabled] = useState(true);

  const readerRef = useRef<HTMLDivElement>(null);
  const FLIP_DURATION = 900;

  useEffect(() => {
    const handleResize = () => setIsSpread(window.innerWidth > 1024);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const totalPages = pages.length;

  const handleNext = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating || currentPage >= totalPages - (isSpread ? 2 : 1)) return;

    if (soundEnabled) playPaperFlipSound();

    setDirection('next');
    setIsAnimating(true);
    setTimeout(() => {
      setCurrentPage(prev => prev + (isSpread ? 2 : 1));
      setIsAnimating(false);
      setDirection(null);
    }, FLIP_DURATION);
  }, [isAnimating, isSpread, currentPage, totalPages, soundEnabled]);

  const handlePrev = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating || currentPage <= 0) return;

    if (soundEnabled) playPaperFlipSound();

    setDirection('prev');
    setIsAnimating(true);
    setTimeout(() => {
      setCurrentPage(prev => prev - (isSpread ? 2 : 1));
      setIsAnimating(false);
      setDirection(null);
    }, FLIP_DURATION);
