          style={{
            background: side === 'left' 
              ? 'linear-gradient(to left, rgba(0,0,0,0.18) 0%, rgba(0,0,0,0.05) 40%, transparent 100%)'
              : 'linear-gradient(to right, rgba(0,0,0,0.18) 0%, rgba(0,0,0,0.05) 40%, transparent 100%)'
          }}
