    const filter = ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(200, t);
    filter.frequency.exponentialRampToValueAtTime(1400, t + 0.15); // Attack
    filter.frequency.exponentialRampToValueAtTime(100, t + 0.6); // Decay

