    noiseGain.gain.setValueAtTime(0, t);
    noiseGain.gain.linearRampToValueAtTime(0.4, t + 0.1);
    noiseGain.gain.exponentialRampToValueAtTime(0.001, t + 0.5);

    noiseSrc.connect(filter);
    filter.connect(noiseGain);
    noiseGain.connect(ctx.destination);

    noiseSrc.start(t);

    // 2. Paper Settle Thud (종이가 닿을 때의 묵직한 소리)
    const thudOsc = ctx.createOscillator();
    thudOsc.type = 'sine';
    thudOsc.frequency.setValueAtTime(60, t + 0.35); // 저음역대

    const thudGain = ctx.createGain();
    thudGain.gain.setValueAtTime(0, t + 0.35);
    thudGain.gain.linearRampToValueAtTime(0.1, t + 0.4);
    thudGain.gain.exponentialRampToValueAtTime(0.001, t + 0.55);

    thudOsc.connect(thudGain);
    thudGain.connect(ctx.destination);
    thudOsc.start(t + 0.35);
    thudOsc.stop(t + 0.6);

  } catch (e) {
    console.error("Audio play failed", e);
  }
};
