// 영상 스타일의 사운드 엔진: "착!" 하는 경쾌하고 빠른 소리
const playPaperFlipSound = () => {
  try {
    const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
    if (!AudioContext) return;

    const ctx = new AudioContext();
    const t = ctx.currentTime;

    // 1. High-Pitch Friction (종이 스치는 날카로운 소리 - "Swish")
    const frictionBuffer = ctx.createBuffer(1, ctx.sampleRate * 0.1, ctx.sampleRate);
    const frictionData = frictionBuffer.getChannelData(0);
    for (let i = 0; i < frictionBuffer.length; i++) {
      frictionData[i] = (Math.random() * 2 - 1) * Math.exp(-i / (ctx.sampleRate * 0.02)); // 감쇠
    }

    const frictionSrc = ctx.createBufferSource();
    frictionSrc.buffer = frictionBuffer;

    const frictionFilter = ctx.createBiquadFilter();
    frictionFilter.type = 'highpass';
    frictionFilter.frequency.value = 800;

    const frictionGain = ctx.createGain();
    frictionGain.gain.setValueAtTime(0.8, t);
    frictionGain.gain.exponentialRampToValueAtTime(0.01, t + 0.1);

    frictionSrc.connect(frictionFilter);
    frictionFilter.connect(frictionGain);
    frictionGain.connect(ctx.destination);
    frictionSrc.start(t);

    // 2. Paper Snap (종이가 넘어간 후 펴질 때 나는 "Thwack" 소리)
    const snapBuffer = ctx.createBuffer(1, ctx.sampleRate * 0.3, ctx.sampleRate);
    const snapData = snapBuffer.getChannelData(0);
    for (let i = 0; i < snapBuffer.length; i++) {
       // 약간의 펄스성 노이즈
       snapData[i] = (Math.random() * 2 - 1);
    }

    const snapSrc = ctx.createBufferSource();
    snapSrc.buffer = snapBuffer;

    const snapFilter = ctx.createBiquadFilter();
    snapFilter.type = 'lowpass';
    snapFilter.frequency.setValueAtTime(600, t + 0.05);
    snapFilter.frequency.exponentialRampToValueAtTime(100, t + 0.2);

    const snapGain = ctx.createGain();
    snapGain.gain.setValueAtTime(0, t);
    snapGain.gain.setValueAtTime(0, t + 0.04); // 약간 딜레이
    snapGain.gain.linearRampToValueAtTime(0.6, t + 0.06); // Attack
    snapGain.gain.exponentialRampToValueAtTime(0.001, t + 0.25); // Decay

    snapSrc.connect(snapFilter);
    snapFilter.connect(snapGain);
    snapGain.connect(ctx.destination);
    snapSrc.start(t);

  } catch (e) {
    console.error("Audio play failed", e);
  }
};

