import * as pdfjsLib from 'pdfjs-dist';
import { PageData } from '../types';

pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://unpkg.com/pdfjs-dist@5.4.530/build/pdf.worker.min.mjs';

export const loadPdfPages = async (file: File): Promise<PageData[]> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const numPages = pdf.numPages;
  const pages: PageData[] = [];

  for (let i = 1; i <= numPages; i++) {
    const page = await pdf.getPage(i);
    // 5.0 스케일 유지 (매우 높은 해상도)
    const viewport = page.getViewport({ scale: 5.0 });
    const canvas = document.createElement('canvas');
    // alpha: false로 설정하여 약간의 성능 이점 및 배경 불투명 처리
    const context = canvas.getContext('2d', { alpha: false });

    if (context) {
      canvas.height = viewport.height;
      canvas.width = viewport.width;

      // 렌더링 품질 최적화
      await page.render({
        canvasContext: context,
        viewport: viewport,
        intent: 'print', // 인쇄 수준의 품질
        background: 'white'
      }).promise;

      // 중요: JPEG 대신 PNG 사용 (압축 노이즈 제거, 텍스트 선명도 극대화)
      const imageUrl = canvas.toDataURL('image/png');
      const textContent = await page.getTextContent();

      const text = textContent.items
        .map((item: any) => ('str' in item ? item.str : ''))
        .join(' ');

      pages.push({ imageUrl, text });
    }
  }

  return pages;
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ChevronLeft, ChevronRight, Maximize2, Minimize2, BookOpen, Sparkles, ArrowLeft, ArrowRight, Volume2, VolumeX, ZoomIn, ZoomOut } from 'lucide-react';
import { PageData, BookMetadata } from '../types';

interface ReaderProps {
  pages: PageData[];
  metadata: BookMetadata | null;
}

// Advanced Procedural Audio Engine for Realistic Paper Physics
const playPaperFlipSound = () => {
  try {
    const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
    if (!AudioContext) return;

    const ctx = new AudioContext();
    const t = ctx.currentTime;

    // Helper: Generate Pink Noise Buffer (Warmer, natural texture)
    const createPinkNoise = (duration: number) => {
      const bufferSize = ctx.sampleRate * duration;
      const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
      const data = buffer.getChannelData(0);
      let b0=0, b1=0, b2=0, b3=0, b4=0, b5=0, b6=0;
      for (let i = 0; i < bufferSize; i++) {
        const white = Math.random() * 2 - 1;
        b0 = 0.99886 * b0 + white * 0.0555179;
        b1 = 0.99332 * b1 + white * 0.0750759;
        b2 = 0.96900 * b2 + white * 0.1538520;
        b3 = 0.86650 * b3 + white * 0.3104856;
        b4 = 0.55000 * b4 + white * 0.5329522;
        b5 = -0.7616 * b5 - white * 0.0168980;
        data[i] = (b0 + b1 + b2 + b3 + b4 + b5 + b6 + white * 0.5362) * 0.11;
        b6 = white * 0.115926;
      }
      return buffer;
    };

    // Layer 1: The "Lift" & "Rustle" (Pink Noise + Bandpass)
    // Simulates the friction of paper sliding against paper
    const rustleBuffer = createPinkNoise(0.8);
    const rustleSrc = ctx.createBufferSource();
    rustleSrc.buffer = rustleBuffer;

    const rustleFilter = ctx.createBiquadFilter();
    rustleFilter.type = 'bandpass';
    rustleFilter.frequency.setValueAtTime(400, t);
    rustleFilter.frequency.linearRampToValueAtTime(800, t + 0.6); // Pitch shift up as velocity increases
    rustleFilter.Q.value = 0.5;

    const rustleGain = ctx.createGain();
    rustleGain.gain.setValueAtTime(0, t);
    rustleGain.gain.linearRampToValueAtTime(0.25, t + 0.1); // Soft attack
    rustleGain.gain.exponentialRampToValueAtTime(0.01, t + 0.6); // Fade out

    rustleSrc.connect(rustleFilter);
    rustleFilter.connect(rustleGain);
    rustleGain.connect(ctx.destination);
    rustleSrc.start(t);

    // Layer 2: Air Resistance / Low Whoosh - REMOVED per user request

    // Layer 3: Soft Landing / Settle (Timed for 1.4s animation, landing around ~1.1s)
    // Gentle thud rather than a sharp snap
    const landTime = t + 1.1;
    const landBuffer = createPinkNoise(0.3);
    const landSrc = ctx.createBufferSource();
    landSrc.buffer = landBuffer;

    const landFilter = ctx.createBiquadFilter();
    landFilter.type = 'lowpass';
    landFilter.frequency.setValueAtTime(600, landTime);
    landFilter.frequency.exponentialRampToValueAtTime(150, landTime + 0.15); // Quick dampening

    const landGain = ctx.createGain();
    landGain.gain.setValueAtTime(0, landTime);
    landGain.gain.linearRampToValueAtTime(0.2, landTime + 0.05); 
    landGain.gain.exponentialRampToValueAtTime(0.001, landTime + 0.2);

    landSrc.connect(landFilter);
    landFilter.connect(landGain);
    landGain.connect(ctx.destination);
    landSrc.start(landTime);

  } catch (e) {
    console.error("Audio play failed", e);
  }
};

const Reader: React.FC<ReaderProps> = ({ pages, metadata }) => {
  const [currentPage, setCurrentPage] = useState(0);
  const [isSpread, setIsSpread] = useState(window.innerWidth > 1024);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'next' | 'prev' | null>(null);
  const [soundEnabled, setSoundEnabled] = useState(true);

  // 줌 및 팬(Pan) 상태 관리
  const [zoomScale, setZoomScale] = useState(1.0);
  const [panPos, setPanPos] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);

  // 드래그 시작 시점의 마우스 위치와 팬 위치 간의 차이를 저장
  const dragStartRef = useRef({ x: 0, y: 0 });
  const readerRef = useRef<HTMLDivElement>(null);

  // 자연스러운 슬로우 모션 (1.4초)
  const FLIP_DURATION = 1400;

  useEffect(() => {
    const handleResize = () => setIsSpread(window.innerWidth > 1024);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // 줌이 1.0 이하로 돌아오면 위치 초기화
  useEffect(() => {
    if (zoomScale <= 1.0) {
      setPanPos({ x: 0, y: 0 });
    }
  }, [zoomScale]);

  // 마우스 드래그 이벤트 핸들러 (전역 window 이벤트로 처리하여 끊김 방지)
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      e.preventDefault();
      const newX = e.clientX - dragStartRef.current.x;
      const newY = e.clientY - dragStartRef.current.y;
      setPanPos({ x: newX, y: newY });
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging]);

  const handleMouseDown = (e: React.MouseEvent) => {
    // 확대된 상태에서만 드래그 허용
    if (zoomScale > 1.0) {
      setIsDragging(true);
      dragStartRef.current = {
        x: e.clientX - panPos.x,
        y: e.clientY - panPos.y
      };
    }
  };

  const totalPages = pages.length;

  const handleNext = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating || currentPage >= totalPages - (isSpread ? 2 : 1)) return;

    if (soundEnabled) playPaperFlipSound();

    setDirection('next');
    setIsAnimating(true);
    setTimeout(() => {
      setCurrentPage(prev => prev + (isSpread ? 2 : 1));
      setIsAnimating(false);
      setDirection(null);
    }, FLIP_DURATION);
  }, [isAnimating, isSpread, currentPage, totalPages, soundEnabled]);

  const handlePrev = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating || currentPage <= 0) return;

    if (soundEnabled) playPaperFlipSound();

    setDirection('prev');
    setIsAnimating(true);
    setTimeout(() => {
      setCurrentPage(prev => prev - (isSpread ? 2 : 1));
      setIsAnimating(false);
      setDirection(null);
    }, FLIP_DURATION);
  }, [isAnimating, isSpread, currentPage, soundEnabled]);

  const handleWheel = useCallback((e: React.WheelEvent) => {
    // 휠로 줌 조절
    const sensitivity = 0.001;
    const delta = -e.deltaY * sensitivity;
    setZoomScale(prev => Math.min(Math.max(prev + delta, 0.5), 3.0));
  }, []);

  const leftThickness = Math.min((currentPage / totalPages) * 12, 12);
  const rightThickness = Math.min(((totalPages - currentPage) / totalPages) * 12, 12);

  const renderPageImage = (index: number, side: 'left' | 'right', extraClasses: string = "") => {
    if (index < 0 || index >= totalPages) {
      return <div className={`w-full h-full bg-[#fdfcf9] ${extraClasses}`} />;
    }

    return (
      <div className={`w-full h-full bg-[#fdfcf9] relative overflow-hidden shadow-sm ${extraClasses}`}>
        <img 
          src={pages[index].imageUrl} 
          className="w-full h-full object-contain select-none pointer-events-none" // 이미지 자체 드래그 방지
          // imageRendering 속성 제거하여 브라우저의 고품질 보간 사용
          alt={`Page ${index + 1}`} 
        />
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/paper-fibers.png')] opacity-[0.05] pointer-events-none mix-blend-multiply" />

        {/* Spine Gradient */}
        <div 
          className={`absolute inset-y-0 ${side === 'left' ? 'right-0 w-[8%]' : 'left-0 w-[8%]'} pointer-events-none`}
          style={{
            background: side === 'left' 
              ? 'linear-gradient(to left, rgba(0,0,0,0.15) 0%, transparent 100%)'
              : 'linear-gradient(to right, rgba(0,0,0,0.15) 0%, transparent 100%)'
          }}
        />
        <div className="absolute inset-0 shadow-[inset_0_0_20px_rgba(139,69,19,0.03)] pointer-events-none" />
      </div>
    );
  };

  return (
    <div 
      ref={readerRef} 
      className={`flex flex-col h-full bg-[#111] text-white overflow-hidden select-none touch-none font-inter ${zoomScale > 1.0 ? 'cursor-grab active:cursor-grabbing' : 'cursor-default'}`}
      onWheel={handleWheel}
      onMouseDown={handleMouseDown}
    >
      {/* Header */}
      <div className="flex items-center justify-between px-8 py-4 bg-black/60 backdrop-blur-xl border-b border-white/5 z-[100]">
        <div className="flex items-center gap-4">
          <BookOpen className="w-5 h-5 text-indigo-400" />
          <h2 className="text-sm font-semibold text-slate-100 book-font italic tracking-wide truncate max-w-[250px]">
            {metadata?.title || 'Digital Folio'}
          </h2>
        </div>
        <div className="flex items-center gap-3">
          <div className="flex items-center bg-white/5 rounded-full px-3 py-1 mr-2 border border-white/10">
             <ZoomOut className="w-3 h-3 text-slate-400 cursor-pointer hover:text-white" onClick={() => setZoomScale(s => Math.max(0.5, s - 0.2))} />
             <span className="text-[10px] font-mono text-slate-300 mx-2 w-8 text-center">{Math.round(zoomScale * 100)}%</span>
             <ZoomIn className="w-3 h-3 text-slate-400 cursor-pointer hover:text-white" onClick={() => setZoomScale(s => Math.min(3.0, s + 0.2))} />
          </div>
          <button onClick={() => setSoundEnabled(!soundEnabled)} className="p-2 hover:bg-white/10 rounded-full transition-all text-slate-400 hover:text-white">
            {soundEnabled ? <Volume2 className="w-4 h-4" /> : <VolumeX className="w-4 h-4" />}
          </button>
          <button onClick={() => isFullScreen ? document.exitFullscreen() : readerRef.current?.requestFullscreen()} className="p-2 hover:bg-white/10 rounded-full transition-all text-slate-400 hover:text-white">
            {isFullScreen ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
          </button>
        </div>
      </div>

      {/* 3D Stage */}
      <div className="flex-1 relative flex items-center justify-center p-4 md:p-16 overflow-hidden bg-[radial-gradient(circle_at_center,#1a1c23_0%,#000000_100%)]" style={{ perspective: '3000px' }}>

        <div 
          className="relative transition-transform duration-100 ease-out will-change-transform"
          style={{ 
            // translate를 먼저 적용하고 scale을 적용하여 직관적인 움직임 구현
            transform: `translate3d(${panPos.x}px, ${panPos.y}px, 0) scale(${zoomScale})`, 
            transformStyle: 'preserve-3d' 
          }}
        >
          <div 
            className={`relative flex ${isSpread ? 'w-[min(94vw,1100px)]' : 'w-[min(88vw,480px)]'} aspect-[1.414/1] bg-transparent`} 
            style={{ transformStyle: 'preserve-3d' }}
          >
            {/* Spine Sides (두께) */}
            <div 
              className="absolute top-[1px] bottom-[1px] right-full bg-[#e8e6e1] origin-right transition-all duration-500 ease-out border-l border-black/10"
              style={{ 
                width: `${Math.max(2, leftThickness)}px`,
                transform: `rotateY(-15deg) translateZ(-0.5px)`,
                background: `repeating-linear-gradient(90deg, #fdfcf9 0px, #e8e6e1 1px, #d4d2cd 2px)`
              }}
            >
               <div className="absolute inset-0 bg-black/10" />
            </div>
            <div 
              className="absolute top-[1px] bottom-[1px] left-full bg-[#e8e6e1] origin-left transition-all duration-500 ease-out border-r border-black/10"
              style={{ 
                width: `${Math.max(2, rightThickness)}px`,
                transform: `rotateY(15deg) translateZ(-0.5px)`,
                background: `repeating-linear-gradient(90deg, #fdfcf9 0px, #e8e6e1 1px, #d4d2cd 2px)`
              }}
            >
               <div className="absolute inset-0 bg-black/10" />
            </div>

            {/* 1. Base Layer */}
            <div className="absolute inset-0 flex z-0 shadow-2xl" style={{ transformStyle: 'preserve-3d', transform: 'translateZ(-1px)' }}>
               <div className="w-1/2 h-full relative rounded-l-sm bg-[#fdfcf9]">
                 {isAnimating && direction === 'prev' ? renderPageImage(currentPage - 2, 'left') : renderPageImage(currentPage, 'left')}
               </div>
               <div className="w-1/2 h-full relative rounded-r-sm bg-[#fdfcf9]">
                 {isAnimating && direction === 'next' ? renderPageImage(currentPage + 3, 'right') : renderPageImage(currentPage + 1, 'right')}
               </div>
            </div>

            {/* 2. Flipping Page (Animation Layer) */}
            {isAnimating && (
              <div 
                className={`absolute top-0 bottom-0 w-1/2 z-[50] ${direction === 'next' ? 'right-0 origin-left animate-flip-next' : 'left-0 origin-right animate-flip-prev'}`}
                style={{ 
                  transformStyle: 'preserve-3d', 
                  animationDuration: `${FLIP_DURATION}ms`,
                  // 부드러운 시작과 끝 (S-Curve)
                  animationTimingFunction: 'cubic-bezier(0.2, 0.8, 0.2, 1)' 
                }}
              >
                {/* [앞면] */}
                <div className="absolute inset-0 backface-hidden z-20 shadow-xl bg-[#fdfcf9]">
                  {direction === 'next' ? renderPageImage(currentPage + 1, 'right') : renderPageImage(currentPage, 'left')}

                  <div 
                    className={`absolute inset-0 pointer-events-none ${direction === 'next' ? 'animate-curl-shadow-next' : 'animate-curl-shadow-prev'}`} 
                    style={{ animationDuration: `${FLIP_DURATION}ms` }}
                  />

                  <div className="absolute inset-0 animate-specular-sheen" style={{ animationDuration: `${FLIP_DURATION}ms` }} />
                </div>

                {/* [뒷면] */}
                <div 
                  className="absolute inset-0 backface-hidden z-10 bg-[#fdfcf9]" 
                  style={{ transform: 'rotateY(180deg)' }}
                >
                  <div className="w-full h-full">
                    {direction === 'next' ? renderPageImage(currentPage + 2, 'left') : renderPageImage(currentPage - 1, 'right')}
                  </div>

                  <div 
                    className="absolute inset-0 bg-black/5 animate-flip-shadow" 
                    style={{ animationDuration: `${FLIP_DURATION}ms` }} 
                  />
                </div>
              </div>
            )}

            {/* 3. Static Overlay */}
            {!isAnimating && (
              <div className="absolute inset-0 flex z-40" style={{ transformStyle: 'preserve-3d' }}>
                <div className="w-1/2 h-full relative border-r border-black/5">
                  {renderPageImage(currentPage, 'left')}
                </div>
                <div className="w-1/2 h-full relative">
                  {renderPageImage(currentPage + 1, 'right')}
                </div>
              </div>
            )}

            {/* Center Spine Shadow Overlay */}
            <div className="absolute left-1/2 top-0 bottom-0 w-[60px] -translate-x-1/2 z-[60] pointer-events-none"
              style={{
                background: 'linear-gradient(to right, transparent 0%, rgba(0,0,0,0.1) 40%, rgba(0,0,0,0.25) 50%, rgba(0,0,0,0.1) 60%, transparent 100%)',
                mixBlendMode: 'multiply'
              }}
            />

            {/* Navigation Controls */}
            {!isAnimating && (
              <div className="absolute inset-0 z-[110] pointer-events-none">
                {currentPage > 0 && (
                  <button 
                    onClick={handlePrev} 
                    className="absolute bottom-8 left-8 w-14 h-14 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center pointer-events-auto shadow-2xl hover:bg-indigo-500 hover:border-indigo-400 transition-all active:scale-90 group"
                  >
                    <ArrowLeft className="w-6 h-6 text-white group-hover:scale-110 transition-transform" />
                  </button>
                )}
                {currentPage < totalPages - (isSpread ? 2 : 1) && (
                  <button 
                    onClick={handleNext} 
                    className="absolute bottom-8 right-8 w-14 h-14 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center pointer-events-auto shadow-2xl hover:bg-indigo-500 hover:border-indigo-400 transition-all active:scale-90 group"
                  >
                    <ArrowRight className="w-6 h-6 text-white group-hover:scale-110 transition-transform" />
                  </button>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Footer Progress */}
      <div className="bg-black/80 backdrop-blur-xl border-t border-white/5 p-6 z-[100]">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex flex-col">
            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Progress</span>
            <div className="flex items-center gap-2 mt-1">
              <Sparkles className="w-3.5 h-3.5 text-indigo-400" />
              <span className="text-xs font-bold text-slate-300">
                {currentPage + 1} / {totalPages}
              </span>
            </div>
          </div>

          <div className="flex-1 mx-12 h-1 bg-white/10 rounded-full overflow-hidden">
             <div 
               className="h-full bg-indigo-500 transition-all duration-500"
               style={{ width: `${((currentPage + 1) / totalPages) * 100}%` }}
             />
          </div>

          <div className="flex gap-2">
            <button onClick={handlePrev} disabled={isAnimating || currentPage === 0} className="p-3 bg-white/5 rounded-xl hover:bg-white/10 disabled:opacity-10 transition-all">
              <ChevronLeft className="w-5 h-5 text-slate-400" />
            </button>
            <button onClick={handleNext} disabled={isAnimating || currentPage >= totalPages - (isSpread ? 2 : 1)} className="p-3 bg-white/5 rounded-xl hover:bg-white/10 disabled:opacity-10 transition-all">
              <ChevronRight className="w-5 h-5 text-slate-400" />
            </button>
          </div>
        </div>
      </div>

      <style>{`
        /* 페이지 턴 애니메이션 */
        @keyframes flip-next {
          0% { transform: rotateY(0deg); }
          100% { transform: rotateY(-180deg); }
        }

        @keyframes flip-prev {
          0% { transform: rotateY(0deg); }
          100% { transform: rotateY(180deg); }
        }

        @keyframes curl-shadow-next {
          0% { background: linear-gradient(90deg, rgba(0,0,0,0) 0%, rgba(0,0,0,0) 100%); }
          15% { background: linear-gradient(90deg, rgba(0,0,0,0.05) 80%, rgba(0,0,0,0.2) 100%); }
          50% { background: linear-gradient(90deg, rgba(0,0,0,0) 0%, rgba(0,0,0,0.1) 50%, rgba(0,0,0,0) 100%); }
          100% { background: linear-gradient(90deg, rgba(0,0,0,0.2) 0%, rgba(0,0,0,0) 20%); }
        }

        @keyframes curl-shadow-prev {
          0% { background: linear-gradient(-90deg, rgba(0,0,0,0) 0%, rgba(0,0,0,0) 100%); }
          15% { background: linear-gradient(-90deg, rgba(0,0,0,0.05) 80%, rgba(0,0,0,0.2) 100%); }
          50% { background: linear-gradient(-90deg, rgba(0,0,0,0) 0%, rgba(0,0,0,0.1) 50%, rgba(0,0,0,0) 100%); }
          100% { background: linear-gradient(-90deg, rgba(0,0,0,0.2) 0%, rgba(0,0,0,0) 20%); }
        }

        @keyframes specular-sheen {
          0% { background: linear-gradient(90deg, transparent 0%, transparent 100%); }
          50% { background: linear-gradient(90deg, transparent 40%, rgba(255,255,255,0.1) 50%, transparent 60%); }
          100% { background: linear-gradient(90deg, transparent 0%, transparent 100%); }
        }

        @keyframes flip-shadow {
          0% { opacity: 0; }
          20% { opacity: 0.1; }
          100% { opacity: 0; }
        }

        .animate-flip-next { animation-name: flip-next; animation-fill-mode: forwards; }
        .animate-flip-prev { animation-name: flip-prev; animation-fill-mode: forwards; }
        .animate-curl-shadow-next { animation-name: curl-shadow-next; animation-fill-mode: forwards; }
        .animate-curl-shadow-prev { animation-name: curl-shadow-prev; animation-fill-mode: forwards; }
        .animate-specular-sheen { animation-name: specular-sheen; animation-fill-mode: forwards; }
        .animate-flip-shadow { animation-name: flip-shadow; animation-fill-mode: forwards; }

        .backface-hidden {
          backface-visibility: hidden;
          -webkit-backface-visibility: hidden;
        }
      `}</style>
    </div>
  );
};

export default Reader;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ChevronLeft, ChevronRight, Maximize2, Minimize2, BookOpen, Sparkles, ArrowLeft, ArrowRight, Volume2, VolumeX, ZoomIn, ZoomOut, LogOut } from 'lucide-react';
import { PageData, BookMetadata } from '../types';

interface ReaderProps {
  pages: PageData[];
  metadata: BookMetadata | null;
  onExit: () => void;
}

// Advanced Procedural Audio Engine for Realistic Paper Physics
const playPaperFlipSound = () => {
  try {
    const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
    if (!AudioContext) return;

    const ctx = new AudioContext();
    const t = ctx.currentTime;

    // Helper: Generate Pink Noise Buffer (Warmer, natural texture)
    const createPinkNoise = (duration: number) => {
      const bufferSize = ctx.sampleRate * duration;
      const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
      const data = buffer.getChannelData(0);
      let b0=0, b1=0, b2=0, b3=0, b4=0, b5=0, b6=0;
      for (let i = 0; i < bufferSize; i++) {
        const white = Math.random() * 2 - 1;
        b0 = 0.99886 * b0 + white * 0.0555179;
        b1 = 0.99332 * b1 + white * 0.0750759;
        b2 = 0.96900 * b2 + white * 0.1538520;
        b3 = 0.86650 * b3 + white * 0.3104856;
        b4 = 0.55000 * b4 + white * 0.5329522;
        b5 = -0.7616 * b5 - white * 0.0168980;
        data[i] = (b0 + b1 + b2 + b3 + b4 + b5 + b6 + white * 0.5362) * 0.11;
        b6 = white * 0.115926;
      }
      return buffer;
    };

    // Layer 1: Lift & Rustle - REMOVED per user request
    // Layer 2: Air Whoosh - REMOVED per user request

    // Layer 3: Soft Landing / Settle (Timed for 1.4s animation, landing around ~1.1s)
    // Gentle thud rather than a sharp snap
    const landTime = t + 1.1;
    const landBuffer = createPinkNoise(0.3);
    const landSrc = ctx.createBufferSource();
    landSrc.buffer = landBuffer;

    const landFilter = ctx.createBiquadFilter();
    landFilter.type = 'lowpass';
    landFilter.frequency.setValueAtTime(600, landTime);
    landFilter.frequency.exponentialRampToValueAtTime(150, landTime + 0.15); // Quick dampening

    const landGain = ctx.createGain();
    landGain.gain.setValueAtTime(0, landTime);
    // 볼륨을 0.2 -> 0.05로 대폭 감소 (거슬리지 않게)
    landGain.gain.linearRampToValueAtTime(0.05, landTime + 0.05); 
    landGain.gain.exponentialRampToValueAtTime(0.001, landTime + 0.2);

    landSrc.connect(landFilter);
    landFilter.connect(landGain);
    landGain.connect(ctx.destination);
    landSrc.start(landTime);

  } catch (e) {
    console.error("Audio play failed", e);
  }
};

const Reader: React.FC<ReaderProps> = ({ pages, metadata, onExit }) => {
  const [currentPage, setCurrentPage] = useState(0);
  const [isSpread, setIsSpread] = useState(window.innerWidth > 1024);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'next' | 'prev' | null>(null);
  const [soundEnabled, setSoundEnabled] = useState(true);

  // 줌 및 팬(Pan) 상태 관리
  const [zoomScale, setZoomScale] = useState(1.0);
  const [panPos, setPanPos] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);

  // 드래그 시작 시점의 마우스 위치와 팬 위치 간의 차이를 저장
  const dragStartRef = useRef({ x: 0, y: 0 });
  const readerRef = useRef<HTMLDivElement>(null);

  // 자연스러운 슬로우 모션 (1.4초)
  const FLIP_DURATION = 1400;

  useEffect(() => {
    const handleResize = () => setIsSpread(window.innerWidth > 1024);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // 줌이 1.0 이하로 돌아오면 위치 초기화
  useEffect(() => {
    if (zoomScale <= 1.0) {
      setPanPos({ x: 0, y: 0 });
    }
  }, [zoomScale]);

  // 마우스 드래그 이벤트 핸들러 (전역 window 이벤트로 처리하여 끊김 방지)
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      e.preventDefault();
      const newX = e.clientX - dragStartRef.current.x;
      const newY = e.clientY - dragStartRef.current.y;
      setPanPos({ x: newX, y: newY });
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging]);

  const handleMouseDown = (e: React.MouseEvent) => {
    // 확대된 상태에서만 드래그 허용
    if (zoomScale > 1.0) {
      setIsDragging(true);
      dragStartRef.current = {
        x: e.clientX - panPos.x,
        y: e.clientY - panPos.y
      };
    }
  };

  const totalPages = pages.length;

  const handleNext = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating || currentPage >= totalPages - (isSpread ? 2 : 1)) return;

    if (soundEnabled) playPaperFlipSound();

    setDirection('next');
    setIsAnimating(true);
    setTimeout(() => {
      setCurrentPage(prev => prev + (isSpread ? 2 : 1));
      setIsAnimating(false);
      setDirection(null);
    }, FLIP_DURATION);
  }, [isAnimating, isSpread, currentPage, totalPages, soundEnabled]);

  const handlePrev = useCallback((e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (isAnimating || currentPage <= 0) return;

    if (soundEnabled) playPaperFlipSound();

    setDirection('prev');
    setIsAnimating(true);
    setTimeout(() => {
      setCurrentPage(prev => prev - (isSpread ? 2 : 1));
      setIsAnimating(false);
      setDirection(null);
    }, FLIP_DURATION);
  }, [isAnimating, isSpread, currentPage, soundEnabled]);

  const handleWheel = useCallback((e: React.WheelEvent) => {
    // 휠로 줌 조절
    const sensitivity = 0.001;
    const delta = -e.deltaY * sensitivity;
    setZoomScale(prev => Math.min(Math.max(prev + delta, 0.5), 3.0));
  }, []);

  const leftThickness = Math.min((currentPage / totalPages) * 12, 12);
  const rightThickness = Math.min(((totalPages - currentPage) / totalPages) * 12, 12);

  const renderPageImage = (index: number, side: 'left' | 'right', extraClasses: string = "") => {
    if (index < 0 || index >= totalPages) {
      return <div className={`w-full h-full bg-[#fdfcf9] ${extraClasses}`} />;
    }

    return (
      <div className={`w-full h-full bg-[#fdfcf9] relative overflow-hidden shadow-sm ${extraClasses}`}>
        <img 
          src={pages[index].imageUrl} 
          className="w-full h-full object-contain select-none pointer-events-none" // 이미지 자체 드래그 방지
          // imageRendering 속성 제거하여 브라우저의 고품질 보간 사용
          alt={`Page ${index + 1}`} 
        />
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/paper-fibers.png')] opacity-[0.05] pointer-events-none mix-blend-multiply" />

        {/* Spine Gradient */}
        <div 
          className={`absolute inset-y-0 ${side === 'left' ? 'right-0 w-[8%]' : 'left-0 w-[8%]'} pointer-events-none`}
          style={{
            background: side === 'left' 
              ? 'linear-gradient(to left, rgba(0,0,0,0.15) 0%, transparent 100%)'
              : 'linear-gradient(to right, rgba(0,0,0,0.15) 0%, transparent 100%)'
          }}
        />
        <div className="absolute inset-0 shadow-[inset_0_0_20px_rgba(139,69,19,0.03)] pointer-events-none" />
      </div>
    );
  };

  return (
    <div 
      ref={readerRef} 
      className={`flex flex-col h-full bg-[#111] text-white overflow-hidden select-none touch-none font-inter ${zoomScale > 1.0 ? 'cursor-grab active:cursor-grabbing' : 'cursor-default'}`}
      onWheel={handleWheel}
      onMouseDown={handleMouseDown}
    >
      {/* Header */}
      <div className="flex items-center justify-between px-8 py-4 bg-black/60 backdrop-blur-xl border-b border-white/5 z-[100]">
        <div className="flex items-center gap-4">
          <BookOpen className="w-5 h-5 text-indigo-400" />
          <h2 className="text-sm font-semibold text-slate-100 book-font italic tracking-wide truncate max-w-[250px]">
            {metadata?.title || 'Digital Folio'}
          </h2>
        </div>
        <div className="flex items-center gap-3">
          <div className="flex items-center bg-white/5 rounded-full px-3 py-1 mr-2 border border-white/10">
             <ZoomOut className="w-3 h-3 text-slate-400 cursor-pointer hover:text-white" onClick={() => setZoomScale(s => Math.max(0.5, s - 0.2))} />
             <span className="text-[10px] font-mono text-slate-300 mx-2 w-8 text-center">{Math.round(zoomScale * 100)}%</span>
             <ZoomIn className="w-3 h-3 text-slate-400 cursor-pointer hover:text-white" onClick={() => setZoomScale(s => Math.min(3.0, s + 0.2))} />
          </div>
          <button onClick={() => setSoundEnabled(!soundEnabled)} className="p-2 hover:bg-white/10 rounded-full transition-all text-slate-400 hover:text-white">
            {soundEnabled ? <Volume2 className="w-4 h-4" /> : <VolumeX className="w-4 h-4" />}
          </button>
          <button onClick={() => isFullScreen ? document.exitFullscreen() : readerRef.current?.requestFullscreen()} className="p-2 hover:bg-white/10 rounded-full transition-all text-slate-400 hover:text-white">
            {isFullScreen ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
          </button>
        </div>
      </div>

      {/* 3D Stage */}
      <div className="flex-1 relative flex items-center justify-center p-4 md:p-16 overflow-hidden bg-[radial-gradient(circle_at_center,#1a1c23_0%,#000000_100%)]" style={{ perspective: '3000px' }}>

        <div 
          className="relative transition-transform duration-100 ease-out will-change-transform"
          style={{ 
            // translate를 먼저 적용하고 scale을 적용하여 직관적인 움직임 구현
            transform: `translate3d(${panPos.x}px, ${panPos.y}px, 0) scale(${zoomScale})`, 
            transformStyle: 'preserve-3d' 
          }}
        >
          <div 
            className={`relative flex ${isSpread ? 'w-[min(94vw,1100px)]' : 'w-[min(88vw,480px)]'} aspect-[1.414/1] bg-transparent`} 
            style={{ transformStyle: 'preserve-3d' }}
          >
            {/* Spine Sides (두께) */}
            <div 
              className="absolute top-[1px] bottom-[1px] right-full bg-[#e8e6e1] origin-right transition-all duration-500 ease-out border-l border-black/10"
              style={{ 
                width: `${Math.max(2, leftThickness)}px`,
                transform: `rotateY(-15deg) translateZ(-0.5px)`,
                background: `repeating-linear-gradient(90deg, #fdfcf9 0px, #e8e6e1 1px, #d4d2cd 2px)`
              }}
            >
               <div className="absolute inset-0 bg-black/10" />
            </div>
            <div 
              className="absolute top-[1px] bottom-[1px] left-full bg-[#e8e6e1] origin-left transition-all duration-500 ease-out border-r border-black/10"
              style={{ 
                width: `${Math.max(2, rightThickness)}px`,
                transform: `rotateY(15deg) translateZ(-0.5px)`,
                background: `repeating-linear-gradient(90deg, #fdfcf9 0px, #e8e6e1 1px, #d4d2cd 2px)`
              }}
            >
               <div className="absolute inset-0 bg-black/10" />
            </div>

            {/* 1. Base Layer */}
            <div className="absolute inset-0 flex z-0 shadow-2xl" style={{ transformStyle: 'preserve-3d', transform: 'translateZ(-1px)' }}>
               <div className="w-1/2 h-full relative rounded-l-sm bg-[#fdfcf9]">
                 {isAnimating && direction === 'prev' ? renderPageImage(currentPage - 2, 'left') : renderPageImage(currentPage, 'left')}
               </div>
               <div className="w-1/2 h-full relative rounded-r-sm bg-[#fdfcf9]">
                 {isAnimating && direction === 'next' ? renderPageImage(currentPage + 3, 'right') : renderPageImage(currentPage + 1, 'right')}
               </div>
            </div>

            {/* 2. Flipping Page (Animation Layer) */}
            {isAnimating && (
              <div 
                className={`absolute top-0 bottom-0 w-1/2 z-[50] ${direction === 'next' ? 'right-0 origin-left animate-flip-next' : 'left-0 origin-right animate-flip-prev'}`}
                style={{ 
                  transformStyle: 'preserve-3d', 
                  animationDuration: `${FLIP_DURATION}ms`,
                  // 부드러운 시작과 끝 (S-Curve)
                  animationTimingFunction: 'cubic-bezier(0.2, 0.8, 0.2, 1)' 
                }}
              >
                {/* [앞면] */}
                <div className="absolute inset-0 backface-hidden z-20 shadow-xl bg-[#fdfcf9]">
                  {direction === 'next' ? renderPageImage(currentPage + 1, 'right') : renderPageImage(currentPage, 'left')}

                  <div 
                    className={`absolute inset-0 pointer-events-none ${direction === 'next' ? 'animate-curl-shadow-next' : 'animate-curl-shadow-prev'}`} 
                    style={{ animationDuration: `${FLIP_DURATION}ms` }}
                  />

                  <div className="absolute inset-0 animate-specular-sheen" style={{ animationDuration: `${FLIP_DURATION}ms` }} />
                </div>

                {/* [뒷면] */}
                <div 
                  className="absolute inset-0 backface-hidden z-10 bg-[#fdfcf9]" 
                  style={{ transform: 'rotateY(180deg)' }}
                >
                  <div className="w-full h-full">
                    {direction === 'next' ? renderPageImage(currentPage + 2, 'left') : renderPageImage(currentPage - 1, 'right')}
                  </div>

                  <div 
                    className="absolute inset-0 bg-black/5 animate-flip-shadow" 
                    style={{ animationDuration: `${FLIP_DURATION}ms` }} 
                  />
                </div>
              </div>
            )}

            {/* 3. Static Overlay */}
            {!isAnimating && (
              <div className="absolute inset-0 flex z-40" style={{ transformStyle: 'preserve-3d' }}>
                <div className="w-1/2 h-full relative border-r border-black/5">
                  {renderPageImage(currentPage, 'left')}
                </div>
                <div className="w-1/2 h-full relative">
                  {renderPageImage(currentPage + 1, 'right')}
                </div>
              </div>
            )}

            {/* Center Spine Shadow Overlay */}
            <div className="absolute left-1/2 top-0 bottom-0 w-[60px] -translate-x-1/2 z-[60] pointer-events-none"
              style={{
                background: 'linear-gradient(to right, transparent 0%, rgba(0,0,0,0.1) 40%, rgba(0,0,0,0.25) 50%, rgba(0,0,0,0.1) 60%, transparent 100%)',
                mixBlendMode: 'multiply'
              }}
            />

            {/* Navigation Controls (Floating Arrows) */}
            {!isAnimating && (
              <div className="absolute inset-0 z-[110] pointer-events-none">
                {currentPage > 0 && (
                  <button 
                    onClick={handlePrev} 
                    className="absolute bottom-8 left-8 w-14 h-14 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center pointer-events-auto shadow-2xl hover:bg-indigo-500 hover:border-indigo-400 transition-all active:scale-90 group"
                  >
                    <ArrowLeft className="w-6 h-6 text-white group-hover:scale-110 transition-transform" />
                  </button>
                )}
                {currentPage < totalPages - (isSpread ? 2 : 1) && (
                  <button 
                    onClick={handleNext} 
                    className="absolute bottom-8 right-8 w-14 h-14 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center pointer-events-auto shadow-2xl hover:bg-indigo-500 hover:border-indigo-400 transition-all active:scale-90 group"
                  >
                    <ArrowRight className="w-6 h-6 text-white group-hover:scale-110 transition-transform" />
                  </button>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Footer Progress */}
      <div className="bg-black/80 backdrop-blur-xl border-t border-white/5 p-6 z-[100]">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex flex-col">
            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Progress</span>
            <div className="flex items-center gap-2 mt-1">
              <Sparkles className="w-3.5 h-3.5 text-indigo-400" />
              <span className="text-xs font-bold text-slate-300">
                {currentPage + 1} / {totalPages}
              </span>
            </div>
          </div>

          <div className="flex-1 mx-12 h-1 bg-white/10 rounded-full overflow-hidden">
             <div 
               className="h-full bg-indigo-500 transition-all duration-500"
               style={{ width: `${((currentPage + 1) / totalPages) * 100}%` }}
             />
          </div>

          <div className="flex gap-2 items-center">
            <button onClick={handlePrev} disabled={isAnimating || currentPage === 0} className="p-3 bg-white/5 rounded-xl hover:bg-white/10 disabled:opacity-10 transition-all">
              <ChevronLeft className="w-5 h-5 text-slate-400" />
            </button>
            <button onClick={handleNext} disabled={isAnimating || currentPage >= totalPages - (isSpread ? 2 : 1)} className="p-3 bg-white/5 rounded-xl hover:bg-white/10 disabled:opacity-10 transition-all">
              <ChevronRight className="w-5 h-5 text-slate-400" />
            </button>

            <div className="h-6 w-[1px] bg-white/10 mx-1" /> {/* Divider */}

            <button 
              onClick={onExit} 
              className="p-3 bg-red-500/10 rounded-xl hover:bg-red-500/20 border border-red-500/10 transition-all group"
              title="Exit to Home"
            >
              <LogOut className="w-5 h-5 text-red-400 group-hover:text-red-300" />
            </button>
          </div>
        </div>
      </div>

      <style>{`
        /* 페이지 턴 애니메이션 */
        @keyframes flip-next {
          0% { transform: rotateY(0deg); }
          100% { transform: rotateY(-180deg); }
        }

        @keyframes flip-prev {
          0% { transform: rotateY(0deg); }
          100% { transform: rotateY(180deg); }
        }

        @keyframes curl-shadow-next {
          0% { background: linear-gradient(90deg, rgba(0,0,0,0) 0%, rgba(0,0,0,0) 100%); }
          15% { background: linear-gradient(90deg, rgba(0,0,0,0.05) 80%, rgba(0,0,0,0.2) 100%); }
          50% { background: linear-gradient(90deg, rgba(0,0,0,0) 0%, rgba(0,0,0,0.1) 50%, rgba(0,0,0,0) 100%); }
          100% { background: linear-gradient(90deg, rgba(0,0,0,0.2) 0%, rgba(0,0,0,0) 20%); }
        }

        @keyframes curl-shadow-prev {
          0% { background: linear-gradient(-90deg, rgba(0,0,0,0) 0%, rgba(0,0,0,0) 100%); }
          15% { background: linear-gradient(-90deg, rgba(0,0,0,0.05) 80%, rgba(0,0,0,0.2) 100%); }
          50% { background: linear-gradient(-90deg, rgba(0,0,0,0) 0%, rgba(0,0,0,0.1) 50%, rgba(0,0,0,0) 100%); }
          100% { background: linear-gradient(-90deg, rgba(0,0,0,0.2) 0%, rgba(0,0,0,0) 20%); }
        }

        @keyframes specular-sheen {
          0% { background: linear-gradient(90deg, transparent 0%, transparent 100%); }
          50% { background: linear-gradient(90deg, transparent 40%, rgba(255,255,255,0.1) 50%, transparent 60%); }
          100% { background: linear-gradient(90deg, transparent 0%, transparent 100%); }
        }

        @keyframes flip-shadow {
          0% { opacity: 0; }
          20% { opacity: 0.1; }
          100% { opacity: 0; }
        }

        .animate-flip-next { animation-name: flip-next; animation-fill-mode: forwards; }
        .animate-flip-prev { animation-name: flip-prev; animation-fill-mode: forwards; }
        .animate-curl-shadow-next { animation-name: curl-shadow-next; animation-fill-mode: forwards; }
        .animate-curl-shadow-prev { animation-name: curl-shadow-prev; animation-fill-mode: forwards; }
        .animate-specular-sheen { animation-name: specular-sheen; animation-fill-mode: forwards; }
        .animate-flip-shadow { animation-name: flip-shadow; animation-fill-mode: forwards; }

        .backface-hidden {
          backface-visibility: hidden;
          -webkit-backface-visibility: hidden;
        }
      `}</style>
    </div>
  );
};

export default Reader;

import React, { useState, useCallback } from 'react';
/* Added Sparkles to the lucide-react import list */
import { Upload, FileText, Info, AlertCircle, BookOpen, BrainCircuit, X, Compass, Feather, Library, Sparkles } from 'lucide-react';
import { AppState, PageData, BookMetadata } from './types';
import { loadPdfPages } from './services/pdfService';
import { analyzeBookContent } from './services/geminiService';
import Reader from './components/Reader';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.IDLE);
  const [pages, setPages] = useState<PageData[]>([]);
  const [metadata, setMetadata] = useState<BookMetadata | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file || file.type !== 'application/pdf') {
      setError('Please select a valid PDF file.');
      return;
    }

    try {
      setState(AppState.LOADING);
      setError(null);

      const loadedPages = await loadPdfPages(file);
      setPages(loadedPages);

      const sampleText = loadedPages.slice(0, 5).map(p => p.text).join('\n');
      try {
        const meta = await analyzeBookContent(sampleText);
        setMetadata(meta);
      } catch (aiErr) {
        console.error('AI Analysis failed:', aiErr);
        setMetadata({
          title: file.name.replace('.pdf', ''),
          author: 'Unknown Author',
          summary: 'The AI companion could not generate a summary for this document.',
          genre: 'Digital Manuscript',
          keyTakeaways: ['Analysis unavailable']
        });
      }

      setState(AppState.READING);
    } catch (err) {
      console.error(err);
      setError('An error occurred while processing the PDF.');
      setState(AppState.ERROR);
    }
  };

  const reset = () => {
    setState(AppState.IDLE);
    setPages([]);
    setMetadata(null);
    setError(null);
  };

  if (state === AppState.READING) {
    return (
      <div className="flex h-screen bg-[#08090b] overflow-hidden font-inter selection:bg-indigo-500/30">
        {/* Main Reader View */}
        <div className="flex-1 flex flex-col min-w-0">
          <Reader pages={pages} metadata={metadata} onExit={reset} />
        </div>

        {/* AI Analysis Sidebar: Premium Design */}
        <div className={`
          ${isSidebarOpen ? 'w-80 md:w-[400px]' : 'w-0'} 
          bg-[#0c0e12] border-l border-white/5 transition-all duration-500 ease-in-out overflow-hidden relative flex flex-col shadow-[-10px_0_40px_rgba(0,0,0,0.5)]
        `}>
          <div className="p-8 h-full overflow-y-auto custom-scrollbar flex flex-col">
            <div className="flex items-center justify-between mb-10">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-500/10 rounded-lg border border-indigo-500/20">
                  <BrainCircuit className="w-5 h-5 text-indigo-400" />
                </div>
                <h3 className="font-bold text-lg text-slate-100 book-font italic tracking-wide">Lumina Insights</h3>
              </div>
              <button 
                onClick={() => setIsSidebarOpen(false)} 
                className="p-2 hover:bg-white/5 rounded-full transition-all text-slate-500 hover:text-white"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            {metadata && (
              <div className="space-y-8 flex-1">
                <div>
                  <span className="text-[9px] text-indigo-400 font-black uppercase tracking-[0.3em]">Bibliography</span>
                  <h1 className="text-2xl font-bold text-white book-font leading-tight mt-2">{metadata.title}</h1>
                  <p className="text-slate-400 text-sm mt-1 italic">by {metadata.author}</p>
                </div>

                <div className="grid grid-cols-2 gap-3">
                   <div className="p-4 bg-white/5 rounded-2xl border border-white/5 backdrop-blur-sm">
                      <span className="text-[8px] text-slate-500 font-black uppercase tracking-[0.2em]">Genre</span>
                      <p className="text-slate-200 text-xs font-semibold mt-1 truncate">{metadata.genre}</p>
                   </div>
                   <div className="p-4 bg-white/5 rounded-2xl border border-white/5 backdrop-blur-sm">
                      <span className="text-[8px] text-slate-500 font-black uppercase tracking-[0.2em]">Pages</span>
                      <p className="text-slate-200 text-xs font-semibold mt-1">{pages.length} Folios</p>
                   </div>
                </div>

                <div className="space-y-3">
                  <div className="flex items-center gap-2">
                    <Feather className="w-3 h-3 text-indigo-500" />
                    <span className="text-[9px] text-indigo-400 font-black uppercase tracking-[0.3em]">Abstract</span>
                  </div>
                  <p className="text-slate-400 text-[13px] leading-relaxed text-justify font-medium">
                    {metadata.summary}
                  </p>
                </div>

                {metadata.keyTakeaways.length > 0 && (
                  <div className="space-y-4">
                    <div className="flex items-center gap-2">
                       <Library className="w-3 h-3 text-indigo-500" />
                       <span className="text-[9px] text-indigo-400 font-black uppercase tracking-[0.3em]">Thematic Notes</span>
                    </div>
                    <ul className="space-y-4">
                      {metadata.keyTakeaways.map((point, idx) => (
                        <li key={idx} className="group relative pl-8 py-1">
                          <span className="absolute left-0 top-1 text-[10px] font-black text-indigo-500/50 group-hover:text-indigo-400 transition-colors">
                            {(idx + 1).toString().padStart(2, '0')}
                          </span>
                          <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-slate-100 transition-colors">
                            {point}
                          </p>
                        </li>
                      ))}
                    </ul>
                  </div>
                )}

                <div className="pt-8">
                  <button 
                    onClick={reset}
                    className="w-full py-4 text-[10px] font-black uppercase tracking-[0.3em] text-slate-500 hover:text-indigo-400 border border-white/5 rounded-2xl hover:bg-indigo-500/5 transition-all duration-300"
                  >
                    Archive & Return
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Sidebar Toggle Button (Minimal Floating) */}
        {!isSidebarOpen && (
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="fixed right-10 bottom-28 p-5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl shadow-[0_20px_40px_rgba(79,70,229,0.3)] transition-all hover:scale-105 active:scale-95 z-20 group"
          >
            <BrainCircuit className="w-6 h-6" />
            <div className="absolute right-full mr-6 top-1/2 -translate-y-1/2 px-4 py-2 bg-slate-900/90 backdrop-blur text-[10px] font-black uppercase tracking-[0.2em] rounded-xl opacity-0 group-hover:opacity-100 transition-all transform group-hover:translate-x-0 translate-x-4 whitespace-nowrap border border-white/10 text-indigo-300 shadow-2xl">
              Reveal AI Wisdom
            </div>
          </button>
        )}
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#08090b] flex flex-col items-center justify-center p-8 md:p-12 relative overflow-hidden font-inter">
      {/* Decorative Background Elements */}
      <div className="absolute top-[-20%] left-[-10%] w-[60%] h-[60%] bg-indigo-600/10 blur-[150px] rounded-full -z-10 animate-pulse" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-indigo-500/10 blur-[120px] rounded-full -z-10" />

      <div className="max-w-3xl w-full text-center space-y-12">
        <div className="space-y-6">
          <div className="inline-flex relative group">
            <div className="absolute inset-0 bg-indigo-500/30 blur-2xl rounded-full scale-110 group-hover:scale-125 transition-transform" />
            <div className="relative w-20 h-20 bg-white/5 backdrop-blur-xl border border-white/10 rounded-[2rem] flex items-center justify-center text-indigo-400 shadow-2xl">
              <BookOpen className="w-10 h-10" />
            </div>
          </div>
          <div className="space-y-2">
            <h1 className="text-5xl md:text-7xl font-bold text-white book-font italic tracking-tight">
              LuminaBook
            </h1>
            <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.5em] mt-4">
              Digital Manuscript Laboratory
            </p>
          </div>
          <p className="text-slate-400 text-lg md:text-xl font-medium max-w-xl mx-auto leading-relaxed opacity-80">
            Transmute static documents into soulful, 3D interactive experiences powered by deep contextual intelligence.
          </p>
        </div>

        <div className="relative group max-w-xl mx-auto">
          <div className="absolute inset-0 bg-gradient-to-b from-indigo-500/20 to-transparent blur-3xl rounded-[3rem] -z-10 opacity-0 group-hover:opacity-100 transition-opacity duration-700" />

          <div className="bg-white/5 backdrop-blur-2xl p-1 md:p-2 rounded-[2.5rem] border border-white/10 shadow-[0_40px_100px_rgba(0,0,0,0.4)]">
            {error && (
              <div className="m-4 p-4 bg-red-500/10 border border-red-500/20 rounded-2xl flex items-center gap-3 text-red-400 text-xs font-bold uppercase tracking-wider animate-in fade-in slide-in-from-top-4">
                <AlertCircle className="w-4 h-4 flex-shrink-0" />
                {error}
              </div>
            )}

            {state === AppState.LOADING ? (
              <div className="flex flex-col items-center justify-center py-20 space-y-8">
                <div className="relative">
                  <div className="w-24 h-24 border-2 border-indigo-500/20 border-t-indigo-400 rounded-full animate-spin" />
                  <div className="absolute inset-0 flex items-center justify-center">
                    <Feather className="w-8 h-8 text-indigo-400 animate-pulse" />
                  </div>
                </div>
                <div className="space-y-2">
                  <h3 className="text-xl font-bold text-white book-font italic">Transmuting Folio</h3>
                  <p className="text-slate-500 text-[9px] font-black uppercase tracking-[0.3em]">Gemini AI is digesting the context</p>
                </div>
              </div>
            ) : (
              <div className="p-4">
                <label className="relative group/zone flex flex-col items-center justify-center w-full h-80 border-2 border-dashed border-white/10 rounded-[2rem] hover:border-indigo-500/50 hover:bg-white/5 transition-all duration-500 cursor-pointer overflow-hidden">
                  <input 
                    type="file" 
                    accept="application/pdf" 
                    onChange={handleFileUpload}
                    className="hidden" 
                  />

                  <div className="flex flex-col items-center justify-center space-y-6 text-slate-500 group-hover/zone:text-indigo-400 transition-all duration-500">
                    <div className="p-6 bg-white/5 rounded-full border border-white/5 group-hover/zone:scale-110 transition-transform duration-500">
                      <Upload className="w-10 h-10" />
                    </div>
                    <div className="text-center space-y-2">
                      <span className="text-lg font-bold text-slate-300 block">Summon Your Document</span>
                      <p className="text-[10px] font-black uppercase tracking-[0.2em] opacity-60">PDF Archive Required</p>
                    </div>
                  </div>
                </label>
              </div>
            )}
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 pt-8 opacity-60 hover:opacity-100 transition-opacity">
          <FeatureCard 
            icon={<Library className="w-5 h-5" />}
            title="Archives"
            desc="High-fidelity PDF processing"
          />
          <FeatureCard 
            icon={<Compass className="w-5 h-5" />}
            title="Navigation"
            desc="Fluid 3D interaction model"
          />
          <FeatureCard 
            icon={<Sparkles className="w-5 h-5" />}
            title="Oracle"
            desc="Deep generative synthesis"
          />
        </div>

        <div className="pt-12">
           <p className="text-slate-600 text-[9px] font-black uppercase tracking-[0.4em] flex items-center justify-center gap-3">
             <span className="w-8 h-[1px] bg-slate-800" />
             Core Engine: Gemini Flash 2.5
             <span className="w-8 h-[1px] bg-slate-800" />
           </p>
        </div>
      </div>

      <style>{`
        .book-font {
          font-family: 'Crimson Pro', serif;
        }
        .custom-scrollbar::-webkit-scrollbar {
          width: 3px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #1e293b;
          border-radius: 10px;
        }
        @keyframes pulse-slow {
          0%, 100% { opacity: 0.1; }
          50% { opacity: 0.2; }
        }
        .animate-pulse-slow {
          animation: pulse-slow 5s infinite ease-in-out;
        }
      `}</style>
    </div>
  );
};

const FeatureCard: React.FC<{ icon: React.ReactNode, title: string, desc: string }> = ({ icon, title, desc }) => (
  <div className="flex flex-col items-center p-6 rounded-3xl bg-white/5 border border-white/5 text-center group hover:bg-white/10 transition-all cursor-default">
    <div className="text-indigo-400 mb-3 group-hover:scale-110 transition-transform">{icon}</div>
    <h4 className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em]">{title}</h4>
    <p className="text-[11px] text-slate-500 mt-2 font-medium italic">{desc}</p>
  </div>
);

export default App;
